INSERT INTO `recipes` (`id`, `name`, `category`, `area`, `instructions`, `thumbnail`, `all_ingredients`, `all_measures`, `youtube`) VALUES
(52874, 'Beef and Mustard Pie', 'Beef', 'British', 'Preheat oven to 150C. Toss beef in flour, salt, and pepper. Brown the beef in a casserole dish with oil. Add wine, stock, onion, carrots, thyme, and mustard. Cook in oven for 2 hours. Once cooled, transfer to a pie dish, cover with puff pastry, brush with egg yolk, and bake at 200C for 30 minutes. Serve with boiled green beans tossed in butter.', 'https://www.themealdb.com/images/media/meals/sytuqu1511553755.jpg', 'Beef, Plain Flour, Rapeseed Oil, Red Wine, Beef Stock, Onion, Carrots, Thyme, Mustard, Egg Yolks, Puff Pastry, Green Beans, Butter, Salt, Pepper', '1kg, 2 tbs, 2 tbs, 200ml, 400ml, 1 finely sliced, 2 chopped, 3 sprigs, 2 tbs, 2 free-range, 400g, 300g, 25g, pinch, pinch', 'https://www.youtube.com/watch?v=nMyBC9staMU'),
(52904, 'Beef Bourguignon', 'Beef', 'French', 'Heat a casserole pan and fry beef in goose fat until browned. In the same pan, fry bacon, shallots, mushrooms, garlic, and bouquet garni. Mix in tomato puree, return beef to pan. Pour over wine and water. Cook at 150C for 3 hours. If sauce is watery, thicken over high heat. Serve with celeriac mash made by simmering celeriac cubes in water with herbs, then crushing with olive oil.', 'https://www.themealdb.com/images/media/meals/vtqxtu1511784197.jpg', 'Goose Fat, Beef Shin, Bacon, Challots, Chestnut Mushroom, Garlic Clove, Bouquet Garni, Tomato Puree, Red Wine, Celeriac, Olive Oil, Thyme, Rosemary, Bay Leaf, Cardamom', '3 tsp, 600g, 100g, 350g, 250g, 2 sliced, 1, 1 tbs, 750 ml, 600g, 2 tbs, sprigs of fresh, sprigs of fresh, 2, 4', 'https://www.youtube.com/watch?v=SQnr4Z-7rok'),
(53099, 'Aussie Burgers', 'Beef', 'Australian', 'Step 1: Tip the meat into a bowl and sprinkle over salt and pepper. Shape into four burgers. Step 2: Slice the beetroot and split the naan breads. Step 3: Heat a griddle pan. Toast the naans on both sides. Cook the burgers for 2-3 minutes per side. Step 4: Assemble the dish. Put rocket on each naan, top with a burger, beetroot, and soured cream. Serve with salad and chips.', 'https://www.themealdb.com/images/media/meals/44bzep1761848278.jpg', 'Lean Minced Steak, Cooked Beetroot, Naan Bread, Rocket, Soured cream and chive dip', '500g, 100g, 2 small, 50g, 4 tablespoons', 'https://www.youtube.com/watch?v=pSupybydA_U'),
(53334, 'Arepa Pabellón', 'Beef', 'Venezulan', 'Prepare the meat in a skillet and add salt and pepper to taste, heat the beans over medium heat in a pan, fry or grill the ripe plantains as indicated on its package and cut the tomato into small cubes. Preheat the grill or pan and grill the arepa, putting it once on each side until they are golden brown. With the help of a knife, open it by the edge through the middle, creating a space to fill it with the ripe plantain, the beans, meat and chopped tomato. Serve with a little pico de gallo or guacamole dip sauce.', 'https://www.themealdb.com/images/media/meals/13fg4j1764441982.jpg', 'Corn Arepa Filled With Mozarella Cheese, Fried Ripe Bananas, Black Beans, Pico De Gallo Sauce, Shredded Meat, Tomato, Salt, Pepper', '2, 1, 1 Can, 1, 2kg, 1 chopped, Pinch, Pinch', 'https://www.youtube.com/shorts/Tb1PPOyqthA'),
(53071, 'Beef Asado', 'Beef', 'Filipino', '0. Combine beef, crushed peppercorn, soy sauce, vinegar, dried bay leaves, lemon, and tomato sauce. Marinate beef for at least 30 minutes. 1. Put the marinated beef in a cooking pot along with remaining marinade. Add water. Let boil. 2. Add Beef Cube. Stir. Cover the pot and cook for 40 minutes in low heat. 3. Turn the beef over. Add tomato paste. Continue cooking until beef tenderizes. 4. Fry the potato and carrots until they brown. 5. Saute onion and garlic until onion softens. 6. Pour-in the sauce from the beef stew. Let boil. Add the beef. Cook for 2 minutes. 7. Add butter and let it melt. Continue cooking until the sauce reduces to half.', 'https://www.themealdb.com/images/media/meals/pkopc31683207947.jpg', 'Beef, Beef Stock Concentrate, Tomato Puree, Water, Soy Sauce, White Wine Vinegar, Pepper, Bay Leaf, Lemon, Tomato Sauce, Butter, Olive Oil, Onion, Garlic', '1.5kg, 1, 8 ounces, 3 cups, 6 tablespoons, 1 tbs, 2 tbs, 4, 1/2, 2 tbs, 3 tbs, 1/2 cup, 1 chopped, 4 cloves', 'https://www.youtube.com/watch?v=lNlK8DVhXXA'),
(52873, 'Beef Dumpling Stew', 'Beef', 'British', 'Preheat oven to 180C. Fry beef in oil and butter until browned. Sprinkle over flour and cook for 2-3 mins. Add garlic and vegetables, fry for 1-2 mins. Stir in wine, stock, herbs, Worcestershire sauce, and balsamic vinegar. Bake for 2 hours. For dumplings, mix flour, baking powder, salt, suet, and water to form dough. Roll into balls, place on stew, and cook for 20 mins until tender. Serve with mashed potato.', 'https://www.themealdb.com/images/media/meals/uyqrrv1511553350.jpg', 'Olive Oil, Butter, Beef, Plain Flour, Garlic, Onions, Celery, Carrots, Leek, Swede, Red Wine, Beef Stock, Bay Leaf, Thyme, Parsley, Plain Flour, Baking Powder, Suet, Water', '2 tbs, 25g, 750g, 2 tblsp, 2 cloves minced, 175g, 150g, 150g, 2 chopped, 200g, 150ml, 500g, 2, 3 tbs, 3 tblsp chopped, 125g, 1 tsp, 60g, Splash', 'https://www.youtube.com/watch?v=6NgheY-r5t0'),
(53317, 'Beef Empanadas', 'Beef', 'Uruguayan', 'For dough: Knead lard, water, salt, flour, and oregano. Rest for 30 mins. For filling: Sauté onions and garlic, brown meat, add tomatoes and herbs. Simmer and mix with boiled eggs. Roll out dough, cut circles, fill with meat mixture, and seal edges. Preheat oven to 200C. Brush with egg wash and bake for 25 mins until golden. Serve with chimichurri sauce.', 'https://www.themealdb.com/images/media/meals/dxpc7j1764370714.jpg', 'Lard, Water, Salt, All purpose flour, Tomato, Garlic, Red Onions, Spring Onions, Sirloin steak, Dried Oregano, Paprika, Red Pepper Flakes, Parsley, Salt, Pepper, Egg, Egg Wash, Chimichurri sauce', '60g, 340g, 1 tsp, 600g, 3, 1 clove, 1 large, Bunch, 750g, 1 tablespoon, 1 tsp, 1 tsp, 1 tsp, To taste, To taste, 3, Splash, Drizzle', 'https://www.youtube.com/watch?v=RRNVLC6IAv4'),
(53359, 'Beef Mandi', 'Beef', 'Indian', '1. Season beef with salt and turmeric. 2. Sauté onions in ghee until golden. 3. Add garlic, chilies, and tomato. 4. Add mandi spices. 5. Cook beef in spices, then add stock and simmer until tender. 6. Strain broth and cook basmati rice in it. 7. Place beef over rice and steam for 10 mins. 8. Optional: Add smoky flavor using hot charcoal. 9. Serve with salad.', 'https://www.themealdb.com/images/media/meals/1nalo51765188375.jpg', 'Basmati Rice, Beef Stock, Onion, Garlic, Green Chilli, Tomato, Salt, Oil, Turmeric Powder, Cardamom, Cloves, Bay Leaf', '1 kg, 5 Cups, 2 medium, 5 chopped cloves, 2, 1 small, 2 1/2 Tsp, 3 tablespoons, 1 ½ tsp, 1/2 tsp, 1/2 tsp, 1/2 tsp', ''),
(53238, 'Beef pho', 'Beef', 'Vietnamese', '1. Char onion and ginger, then add to beef stock with toasted spices. Simmer for 30 mins and strain. 2. Partially freeze steak for 15 mins to slice thinly. 3. Season broth with sugar, fish sauce, and soy. 4. Place cooked noodles and raw beef slices in bowls. 5. Pour boiling broth over to cook the beef. 6. Top with herbs, chili, and lime.', 'https://www.themealdb.com/images/media/meals/pbzcrx1763765096.jpg', 'Beef Stock, Onion, Ginger, Cinnamon Stick, Star Anise, Coriander Seeds, Cloves, Sirloin steak, Palm Sugar, Fish Sauce, Soy Sauce, Rice Noodles, Spring Onions, Birds-eye Chillies, Basil, Coriander, Lime', '1 L, 1 large, 1 Large Chopped, 1, 2, 1 tsp, 1/2 teaspoon, 225g, 1 tsp, 1 tablespoon, 1 ½ tbsp, 200g, 2 sliced, 1 small, Handful, Handful, 1', 'https://www.youtube.com/watch?v=WlosNFMCnE4'),
(52834, 'Beef stroganoff', 'Beef', 'Russian', '1. Sauté onion and garlic in olive oil until soft. 2. Add butter and mushrooms, cook until softened, then set aside. 3. Toss steak in seasoned flour and fry until colored. 4. Return onions and mushrooms to the pan. 5. Whisk creme fraiche, mustard, and stock, then pour into pan. 6. Simmer for 5 mins. 7. Garnish with parsley and serve with rice or pasta.', 'https://www.themealdb.com/images/media/meals/svprys1511176755.jpg', 'Olive Oil, Onions, Garlic, Butter, Mushrooms, Beef Fillet, Plain Flour, Creme Fraiche, English Mustard, Beef Stock, Parsley', '1 tbls, 1, 1 clove, 1 tbsp, 250g, 500g, 1tbsp, 150g, 1 tbsp, 100ml, Topping', 'https://www.youtube.com/watch?v=PQHgQX1Ss74'),
(53013, 'Big Mac', 'Beef', 'American', '1. For the sauce, combine mayonnaise, vinegar, mustard, onion salt, garlic powder, and paprika. Chill. 2. Form mince into 4 balls, flatten into 15cm circles, and fry for 1-2 mins each side. 3. Slice each burger bun into three layers and toast. 4. Assemble: spread sauce on base, top with onion, lettuce, cheese, patty, and pickles. Add middle bun, more sauce, onion, lettuce, pickles, and the second patty. Top with lid to serve.', 'https://www.themealdb.com/images/media/meals/urzj1d1587670726.jpg', 'Minced Beef, Olive Oil, Sesame Seed Burger Buns, Onion, Iceberg Lettuce, Cheese, Dill Pickles, Mayonnaise, White Wine Vinegar, Pepper, Mustard, Onion Salt, Garlic Powder, Paprika', '400g, 2 tbs, 2, Chopped, 1/4, 2 sliced, 2 large, 1 cup, 2 tsp, Pinch, 2 tsp, 1 1/2 tsp, 1 1/2 tsp, 1/2 tsp', 'https://www.youtube.com/watch?v=C5J39YnnPsg'),
(53311, 'Borsch', 'Beef', 'Ukrainian', '1. Simmer beef, onion, and bay leaf in water for 1.5-3 hours until tender. 2. Add potatoes and cook until soft. 3. Sauté diced onion and carrot in oil until soft. 4. Add beetroot, red pepper, tomatoes, and prunes; simmer briefly then add to the main pot. 5. Add shredded cabbage and kidney beans, cook for 7-10 mins. 6. Serve with sour cream, dill, and crusty bread.', 'https://www.themealdb.com/images/media/meals/804v1j1764367088.jpg', 'Beef Shin, Onion, Bay Leaf, Potatoes, Sunflower Oil, Onion, Carrots, Beetroot, Red Pepper, Tinned Tomatos, Prunes, White Cabbage, Kidney Beans, Creme Fraiche, Dill, Crusty Bread', '1kg, 1, 1, 2.5kg, 2 tablespoons, 1 Diced, 1, 200g, 1 chopped, 200g, 6, 1/2, 400g, 100 ml, Bunch, To serve', 'https://www.youtube.com/watch?v=6CXgPVw_-0g'),
(53078, 'Beetroot Soup (Borscht)', 'Vegetarian', 'Ukrainian', '1. Chop beetroot and cook in water with a stock cube for 15 mins. 2. Add potatoes and other vegetables; boil until soft. 3. Add cannellini beans and cook for 5 more minutes. 4. Garnish with dill and serve warm.', 'https://www.themealdb.com/images/media/meals/zadvgb1699012544.jpg', 'Beetroot, Olive Oil, Chicken Stock Cube, Water, Potatoes, Cannellini Beans, Dill', '3, 4 tbs, 1, 6 cups, 3, 1 can, Garnish', 'https://www.youtube.com/watch?v=6CXgPVw_-0g'),
(53319, 'Chivito sandwich', 'Beef', 'Uruguayan', '1. Make brioche dough: mix heated milk, butter, molasses with water, egg, flour, salt, and yeast. Chill overnight. 2. Shape into balls, let rise, and bake at 220C until golden. 3. Sauté onions until caramelized. 4. Grill steaks with garlic, bacon, and eggs. 5. Assemble: toast buns, spread mustard, layer steak, ham, cheese, bacon, tomato, lettuce, and fried egg. Top with chimichurri and onions.', 'https://www.themealdb.com/images/media/meals/j80gmw1764372176.jpg', 'Milk, Butter, Molasses, Water, Egg, Bread Flour, Salt, Yeast, Egg Wash, Sesame Seed, Onion, Sirloin steak, Garlic, Bacon, Ham, Mozzarella, Tomato, Lettuce, Mustard, Chimichurri sauce', '80g, 60g, 1 tablespoon, 220g, 9, 500g, 10g, 10g, Splash, Sprinkling, 4, 8, To serve, 8, 8 slices, 8 slices, 4, 1/4, To serve, To serve', 'https://www.youtube.com/watch?v=tX3fN9AG_ik'),
(53343, 'Classic Tourtière', 'Beef', 'Canadian', '1. Sauté onion and garlic, then brown ground beef and pork with spices. 2. Add beef broth and grated potato; simmer until liquid is absorbed. Cool completely. 3. Line a pie plate with dough, fill with meat mixture, and cover with top crust. 4. Cut a steam vent and brush with egg wash. 5. Bake at 190C (375F) for 45 mins until golden brown. Let cool before slicing.', 'https://www.themealdb.com/images/media/meals/0sd7ac1764787957.jpg', 'Canola Oil, Onion, Garlic, Ground Beef, Ground Pork, Dried Leaves Of Summer Savoury, Salt, Pepper, Ground Clove, Ground Nutmeg, Bay Leaf, Beef Stock, Russet Potato, Shortcrust Pastry, Egg', '2 tablespoons, 1 chopped, 2 cloves minced, 1 lb, 1 lb, 1 tsp, To taste, To taste, 1/2 tsp, 1/2 tsp, 1, 1 cup, 1 small, 4, 1 beaten', 'https://www.youtube.com/watch?v=PM9TZPUJTiU'),
(53031, 'Egyptian Fatteh', 'Beef', 'Egyptian', '1. Fry pita bread pieces in butter until crisp; season with garlic and cumin. 2. Simmer beef with onion and bouillon for 2 hours until tender. 3. Cook rice with toasted noodles (shareya). 4. Assemble: layer bread, saturate with meat broth, top with rice, add more broth. 5. Top with a thick tomato-vinegar sauce and fried beef chunks.', 'https://www.themealdb.com/images/media/meals/rlwcc51598734603.jpg', 'Beef, Onion, Chicken Stock Cube, Tomatoes, Garlic Clove, Tomato Puree, Rice, Noodles, Butter, Olive Oil, Pita Bread, Cumin, White Wine Vinegar, Salt, Pepper', '1lb, 1, 1, 2, 4, 1 tbs, 2 cups, 1/4 cup, 1/4 cup, 2 cups, 1, 1 tbs, 3 tbs, To taste, To taste', 'https://www.youtube.com/watch?v=WLuOHkDE4A4'),
(53134, 'Empanadas (Argentinian)', 'Beef', 'Argentinian', '1. Make dough with flour, salt, and butter; chill for 30 mins. 2. Cook ground beef with onions and spices; mix with eggs and olives once cooled. 3. Roll dough into circles, fill, fold, and seal edges with a fork. 4. Bake at 200C (400F) for 20-25 mins until golden.', 'https://www.themealdb.com/images/media/meals/q99te31763075494.jpg', 'All purpose flour, Butter, Water, Salt, Ground Beef, Onion, Egg, Green Olives, Cumin, Paprika, Salt, Pepper', '500g, 200g, 120ml, 1 tsp, 500g, 2 chopped, 4 Chopped, 100g, 1 teaspoon, 1 teaspoon, To taste, To taste', 'https://www.youtube.com/watch?v=RRNVLC6IAv4'),
(53324, 'Chocolate empanadas', 'Dessert', 'Uruguayan', '1. Boil condensed milk can for 2.5 hours to make Dulce de Leche. 2. Make cocoa dough with flour, butter, and egg; chill. 3. Roll dough thin, cut 12cm circles, fill with Dulce de Leche, and seal. 4. Bake at 180C for 20-25 mins. 5. Brush with melted butter and sprinkle with cinnamon sugar while warm.', 'https://www.themealdb.com/images/media/meals/u9ezi21764375474.jpg', 'Condensed Milk, All purpose flour, Unsweetened Cocoa, Salt, Butter, Egg, Milk, Butter, Sugar, Cinnamon', '400g, 250g, 25g, Pinch, 125g, 1, 3 tablespoons, 30g, 30g, 1 tsp', 'https://www.youtube.com/watch?v=Cdo14aXSHrA'),
(53040, 'Spring onion and prawn empanadas', 'Seafood', 'Portuguese', '1. Make soft dough with butter, flour, egg yolk, and vinegar; rest for 30 mins. 2. Sauté spring onions, garlic, and prawns until opaque; season well. 3. Roll dough balls into circles, fill with prawn mixture and feta, then fold and crimp. 4. Brush with egg yolk and bake at 180C for 30 mins until crisp.', 'https://www.themealdb.com/images/media/meals/1c5oso1614347493.jpg', 'Spring Onions, Olive Oil, Red Chilli, Garlic, Prawns, Feta, Butter, Plain Flour, Egg, White Wine Vinegar', '1 bunch, Dash, 1 finely sliced, 1 clove, 350g, 75g, 15g, 250g, 1 Seperated, 1/2 tsp', 'https://www.youtube.com/watch?v=Q24haJU-1dI'),
(53211, 'Lemongrass beef stew with noodles', 'Beef', 'Thai', '1. Purée ginger, garlic, lemongrass, coriander, and chilli. 2. Fry purée in oil, add beef, soy, five-spice, sugar, and stock. 3. Simmer covered for 1 hr 15 mins, then uncovered for 15 mins. 4. Serve over rice noodles with lime and fresh herbs.', 'https://www.themealdb.com/images/media/meals/ntafxw1763586291.jpg', 'Ginger, Garlic Clove, Lemongrass Stalks, Coriander Leaves, Red Chilli, Vegetable Oil, Beef, Soy Sauce, Five Spice Powder, Brown Sugar, Beef Stock, Rice Noodles, Lime', '1 tablespoon chopped, 2 chopped, 3, 2 tblsp, 2 sliced, 2 tblsp, 250g, 2 tblsp, 1 tsp, 1 tsp, 400ml, 100g, To serve', ''),
(52827, 'Massaman Beef curry', 'Beef', 'Thai', '1. Roast and chop peanuts. 2. Fry curry paste in coconut cream, then sear beef. 3. Add potatoes, onion, spices, coconut milk, and peanuts. 4. Bake covered at 180C for 2 hours until beef is tender. 5. Serve with jasmine rice and fresh chilli.', 'https://www.themealdb.com/images/media/meals/tvttqv1504640475.jpg', 'Peanuts, Coconut cream, Massaman curry paste, Beef, Potatoes, Onion, Lime, Cinnamon stick, Tamarind paste, Brown sugar, Fish Sauce, chilli, Jasmine Rice', '85g, 400ml can, 4 tbsp, 600g, 450g, 1, 4 leaves, 1, 1 tbsp, 1 tbsp, 1 tbsp, 1 sliced, to serve', 'https://www.youtube.com/watch?v=mVxgZSCU9_g'),
(52876, 'Minced Beef Pie', 'Beef', 'British', '1. Brown beef mince with onion, then stir in tomato purée, flour, mushrooms, beef stock, and Worcestershire sauce. 2. Simmer for 20 mins and let cool. 3. Transfer to a pie dish, cover with shortcrust pastry, and flute the edges. 4. Decorate with pastry leaves and brush with egg yolk. 5. Bake at 200C for 20-25 mins until golden.', 'https://www.themealdb.com/images/media/meals/xwutvy1511555540.jpg', 'Vegetable Oil, Minced Beef, Onion, Tomato Puree, Plain Flour, Mushrooms, Beef Stock, Worcestershire Sauce, Shortcrust Pastry, Egg Yolks', '2 tbs, 500g, 1 chopped, 1 tbls, 1 ½ tbsp, 75g, 250ml, Dash, 400g, 1', 'https://www.youtube.com/watch?v=QY47h-uqq5g'),
(53017, 'Paszteciki (Polish Pasties)', 'Beef', 'Polish', '1. Make a smooth dough with flour, egg yolk, and butter; chill for 30 mins. 2. Sauté onion and rutabaga (swede), then grind with cooked beef. 3. Cook mixture until liquid evaporates, then stir in an egg. 4. Roll dough into a rectangle, fill, fold, and seal. 5. Brush with egg and bake at 350°F (175°C) for 30 mins. Slice diagonally.', 'https://www.themealdb.com/images/media/meals/c9a3l31593261890.jpg', 'Flour, Salt, Egg, Butter, Onion, Swede, Beef Brisket, Eggs, Salt, Pepper', '1 cup, 1/4 tsp, 1 Yolk + 1 whole, 11 tblsp total, 1/3 cup, 1/2 cup, 1/2 lb, 2 Beaten, 1 tsp, 1/4 tsp', 'https://www.youtube.com/watch?v=qANmR6BBJpQ'),
(52930, 'Pate Chinois', 'Beef', 'Canadian', '1. Boil and mash potatoes with butter and milk. 2. Brown onion and minced beef in a skillet. 3. Layer the dish: meat at the bottom, followed by a layer of creamed corn, and topped with mashed potatoes. 4. Sprinkle with paprika and parsley. 5. Bake at 190°C (375°F) for 30 mins, then broil briefly until golden.', 'https://www.themealdb.com/images/media/meals/yyrrxr1511816289.jpg', 'Potatoes, Butter, Milk, Minced Beef, Onion, Creamed Corn, Paprika, Parsley, Salt, Pepper', '4 cups, 60ml, ½ cup, 450g, 1 finely chopped, 500ml, to taste, to taste, Dash, Dash', 'https://www.youtube.com/watch?v=QRFqnLkEv3I'),
(53042, 'Portuguese prego with green piri-piri', 'Beef', 'Portuguese', '1. Rub garlic over steaks, marinate with olive oil, vinegar, and parsley for 1-2 hours. 2. Blend green sauce ingredients (basil, parsley, jalapeno, vinegar, spring onions) until smooth. 3. Sear steaks for 2 mins each side on high heat. 4. Rest steaks on ciabatta halves to soak juices, then slice and assemble with sauce and rocket.', 'https://www.themealdb.com/images/media/meals/ewcikl1614348364.jpg', 'Garlic, Beef Fillet, Olive Oil, Vinegar, Parsley, Ciabatta, Rocket, Basil Leaves, Jalapeno, Spring Onions, Caster Sugar', '1 clove, 2 small, 2 tbs, 2 tbs total, 2 bunches total, 2, 2 handfulls, Small bunch, 1, 2 chopped, 1/2 tsp', 'https://www.youtube.com/watch?v=FbIKfcDEPLA'),
(53217, 'Shawarma chuck roast wrap', 'Beef', 'Saudi Arabian', '1. Combine spices, beef broth, and lemon juice in a slow cooker. 2. Add beef and cook on low for 8-10 hours. 3. Shred meat with forks and mix back into the sauce. 4. Spread garlic sauce on pita, add beef, and fold like a burrito. 5. Grill the wrap on a grill pan until toasted.', 'https://www.themealdb.com/images/media/meals/swo87v1763595282.jpg', 'Chuck Roast, Beef Stock, Lemon Juice, Cumin, Paprika, Salt, Ginger, Turmeric, Cayenne, Cinnamon, Coriander, Clove', '1kg, 1 cup, 3 tbs, 1 tbs, 2 tsp, 1 tsp, 1 tsp, 1 tsp, 1/2 tsp, 1/2 tsp, 1/2 tsp, 1/4 tsp', 'https://www.youtube.com/shorts/YLhyRjyLkcE'),
(52770, 'Spaghetti Bolognese', 'Beef', 'Italian', '1. Fry onion, garlic, and minced beef until browned. 2. Add mushrooms and herbs. 3. Stir in tomatoes, stock, tomato puree, and Worcestershire sauce; simmer for 30 mins. 4. Cook spaghetti and drain. 5. Combine meat sauce with spaghetti and serve with Parmesan cheese.', 'https://www.themealdb.com/images/media/meals/sutysw1468247559.jpg', 'Onions, Olive Oil, Garlic, Lean Minced Beef, Mushrooms, Dried Oregano, Tomatoes, Beef Stock, Tomato Puree, Worcestershire Sauce, Spaghetti, Parmesan', '2, 1tbsp, 1 clove, 500g, 90g, 1tsp, 400g can, 300ml, 1tbsp, 1tbsp, 350g, Topping', 'https://www.youtube.com/watch?v=-gF8d-fitkU'),
(52881, 'Steak and Kidney Pie', 'Beef', 'British', '1. Brown beef and kidneys in oil, then sauté onions. 2. Return meat to pan, coat with flour, add stock, and simmer for 1.5 hours. 3. Season with Worcestershire sauce and let cool. 4. Place meat in a dish, cover with puff pastry, and crimp edges. 5. Brush with beaten egg and bake at 220C for 30-40 mins until golden.', 'https://www.themealdb.com/images/media/meals/qysyss1511558054.jpg', 'Puff Pastry, Egg White, Egg Yolks, Vegetable Oil, Beef, Lamb Kidney, Onions, Plain Flour, Beef Stock, Worcestershire Sauce', '300g, Beaten, Beaten, 2 tbs, 70 ml, 200g, 2 chopped, 30g, 85 ml, Dash', 'https://www.youtube.com/watch?v=oTw5tPt4KmA'),
(52935, 'Steak Diane', 'Beef', 'French', '1. Season steaks and sear in oil for 4-5 mins. 2. Reduce beef stock to 1/2 cup in the same skillet. 3. Sauté garlic, shallots, and mushrooms in butter. 4. Add brandy and flambée. 5. Stir in cream, Dijon, Worcestershire, and reduced stock; return steaks to thicken sauce. 6. Top with parsley and chives.', 'https://www.themealdb.com/images/media/meals/vussxq1511882648.jpg', 'Beef Fillet, Beef Stock, Butter, Garlic, Shallots, Mushrooms, Brandy, Heavy Cream, Dijon Mustard, Worcestershire Sauce, Tabasco Sauce, Parsley, Chives', '4 pieces, 1.5 cups, 2 tbs, 2 cloves, 1 medium, 4 oz, 1/4 cup, 1/4 cup, 1 tbs, 1 tbs, Dash, 1 tbs, 1 tbs', 'https://www.youtube.com/watch?v=9rWZNHkrsNg'),
(53199, 'Thai beef stir-fry', 'Beef', 'Thai', '1. Heat oil in a smoking hot wok. 2. Add beef strips and sliced chili, stir-frying for 3 mins until browned. 3. Pour over oyster sauce and cook until it coats the meat. 4. Stir in fresh basil leaves. 5. Serve immediately with plain rice.', 'https://www.themealdb.com/images/media/meals/kyuxew1763479470.jpg', 'Vegetable Oil, Beef, Red Chilli, Oyster Sauce, Basil Leaves', '2 tbsp, 400g, 1 sliced, 2 tblsp, Handful', 'https://www.youtube.com/watch?v=N3OI_7zu5sA'),
(53354, 'Jamaican Curry Goat', 'Goat', 'Jamaican', '1. Rinse goat with vinegar/water. Marinate with curry, ginger, allspice, onion, garlic, and thyme for 4+ hours. 2. Sauté meat in oil using a pressure cooker until brown. 3. Sauté onions and garlic separately, then add back the meat and water. 4. Pressure cook on high for 40 mins, then natural release for 10 mins. 5. Sauté for 10-15 mins with potatoes and a whole scotch bonnet pepper until potatoes are soft.', 'https://www.themealdb.com/images/media/meals/uc9qp11764796575.jpg', 'Goat Meat, Jamaican Curry Powder, Ground Ginger, All-purpose Seasoning, Allspice, Onion, Garlic, Thyme, Oil, Water, Scotch Bonnet, Russet Potato', '3 Lbs, 2.5 tbsp, 1/2 tsp, 1/2 tsp, 1/4 tsp, 1 chopped, 6 cloves, 3 sprigs, 2 tbsp, 1 1/4 cup, 1, 1 large', 'https://www.youtube.com/watch?v=SrX2KMsWbF4'),
(52968, 'Mbuzi Choma (Roasted Goat)', 'Goat', 'Kenyan', '1. Roast goat meat over medium heat for 50 minutes, salting as you turn. 2. For Ugali: Boil salted water, slowly stir in corn flour until thick (10 mins), then form into a ball. 3. For Kachumbari: Mix diced tomatoes, onions, chili, and coriander in a bowl. 4. Serve the roasted meat with hot Ugali and fresh Kachumbari salad.', 'https://www.themealdb.com/images/media/meals/cuio7s1555492979.jpg', 'Goat Meat, Corn Flour, Tomatoes, Salt, Onion, Green Chilli, Coriander Leaves', '1 kg, 1 kg, 2, Pinch, 1, 1, 1 bunch', ''),
(52920, 'Chicken Marengo', 'Chicken', 'French', 'Heat oil in a large flameproof casserole dish and stir-fry the mushrooms until they start to soften. Add the chicken legs and cook briefly on each side to color them a little. Pour in the passata, crumble in the stock cube and stir in the olives. Season with black pepper. Cover and simmer for 40 mins until the chicken is tender. Sprinkle with parsley and serve with pasta, salad, or mashed potatoes.', 'https://www.themealdb.com/images/media/meals/qpxvuq1511798906.jpg', 'Olive Oil, Mushrooms, Chicken Legs, Passata, Chicken Stock Cube, Black Olives, Parsley', '1 tbs, 300g, 4, 500g, 1, 100g, Chopped', 'https://www.youtube.com/watch?v=U33HYUr-0Fw'),
(52831, 'Chicken Karaage', 'Chicken', 'Japanese', 'Whisk ginger, garlic, soy sauce, sake, and sugar in a bowl. Add chicken, coat evenly, and refrigerate for at least 1 hour. Heat 1 inch of vegetable oil in a heavy pot to 360F (180C). Put potato starch in a bowl. Toss a handful of chicken in the starch to coat evenly. Fry in batches until medium brown and cooked through. Transfer to paper towels. For extra crispiness, fry a second time after cooling once. Serve with lemon wedges.', 'https://www.themealdb.com/images/media/meals/tyywsw1505930373.jpg', 'Chicken, Ginger, Garlic, Soy sauce, Sake, Sugar, Potato starch, Vegetable oil, Lemon', '450g, 1 tbsp, 1 clove, 2 tbsp, 1 tbsp, 2 tsp, 1/3 cup, 1/3 cup, 1/3 cup', 'https://www.youtube.com/watch?v=XivddFddthc'),
(52956, 'Chicken Congee', 'Chicken', 'Chinese', 'STEP 1: In a bowl, mix chicken, salt, white pepper, and ginger juice. Set aside. STEP 2: Rinse the rice and drain. STEP 3: Add 8 cups of water to a pot and bring to a boil. Once boiling, add rice, reduce to low heat and stir every 8-10 minutes for about 20-25 minutes. If it is too thick, add a little more water to reach your preferred consistency. Add the marinated chicken to the porridge and simmer on low heat for another 10 minutes. Finally, add green onions, sliced ginger, a pinch of salt and pepper. Stir for 10 seconds and serve hot. Optional: Garnish with coriander.', 'https://www.themealdb.com/images/media/meals/1529446352.jpg', 'Chicken, Salt, Pepper, Ginger Juice, Ginger, Spring Onions, Rice, Water, Coriander', '8 oz, pinch, pinch, 1 tsp, 1 tsp, 1 tbs, 1/2 cup, 8 cups, 2 oz', 'https://www.youtube.com/watch?v=kqEfk801E94'),
(53358, 'Chicken Mandi', 'Chicken', 'Indian', '1. Clean and cut the chicken; marinate briefly with salt, turmeric and a little oil. 2. Rinse and soak basmati rice 20–30 minutes. 3. In a large pot, heat ghee/oil. Fry chopped onion until golden. Add minced garlic and green chillies and fry 1–2 min. 4. Add whole spices (cardamom, cloves, cinnamon, bay leaves) and ground spices (coriander, cumin). 5. Add chicken pieces, brown lightly and add enough water to cover. Simmer until chicken is nearly cooked. 6. Remove chicken, add soaked rice to the liquid. Cook until almost done. 7. Return chicken to the rice pot, cover tightly and steam on low for 10–15 min. 8. Optional: Place a red-hot charcoal in a foil cup in the center, add oil to the coal and cover to trap smoke for 5-10 mins. Garnish and serve.', 'https://www.themealdb.com/images/media/meals/er4d081765186828.jpg', 'Chicken, Basmati Rice, Water, Onion, Garlic, Green Chilli, Salt, Oil, Turmeric, Coriander, Cardamom, Cloves, Cinnamon, Pepper, Bay Leaf', '1, 2 cups, 4 cups, 1 large, 4 cloves, 2, 1.5 tsp, 3 tbsp, 1 tbsp, 1 tsp, ½ tbsp, ¼ tsp, ½ tsp, 1 tsp, 2', ''),
(52795, 'Chicken Handi', 'Chicken', 'Indian', 'Heat oil in a large pot. Add sliced onion and fry until deep golden brown; set aside. Add chopped garlic and sauté for a minute, then add chopped tomatoes and cook until soft (about 5 mins). Return fried onions to the pot, add ginger paste and sauté. Add cumin seeds, coriander seeds, and chopped green chillies. Add turmeric and red chilli powder; sauté for a couple of minutes. Add chicken pieces, season with salt, and cook covered on medium-low heat for 15 minutes. When oil separates, add beaten yogurt on lowest heat. Add half of the dried fenugreek leaves. Finally, add cream, sprinkle remaining fenugreek and garam masala. Serve hot with naan.', 'https://www.themealdb.com/images/media/meals/wyxwsp1486979827.jpg', 'Chicken, Onion, Tomatoes, Garlic, Ginger paste, Oil, Cumin, Coriander seeds, Turmeric, Chilli powder, Green chilli, Yogurt, Cream, Fenugreek, Garam masala', '1.2 kg, 5 sliced, 2, 8 cloves, 1 tbsp, ¼ cup, 2 tsp, 3 tsp, 1 tsp, 1 tsp, 2, 1 cup, ¾ cup, 3 tsp, 1 tsp', 'https://www.youtube.com/watch?v=IO0issT0Rmc'),
(53085, '15-minute chicken & halloumi burgers', 'Chicken', 'American', 'STEP 1: Put the chicken breasts between two pieces of baking parchment and use a rolling pin to gently bash them until they are approximately 1cm thick. Cut each chicken breast into two even pieces. STEP 2: Heat two frying pans over medium-high heat, with one of them containing oil. Fry the chicken in the oiled pan for 3-4 mins on each side until cooked through. Season the chicken, reduce the heat, drizzle in the chilli sauce and half of the lemon juice, and cook for an additional 1-2 mins. STEP 3 (Air-fryer option): Preheat to 180C for 4 mins. Cook chicken for 12 mins, then add sauce and lemon juice for 1-2 mins. STEP 4: Toast the buns in a dry pan for 30 seconds. Cook halloumi until golden. Toss cabbage with mayo and remaining lemon juice. STEP 5: Assemble buns with hummus, rocket, chicken, halloumi, and peppers. Top with cabbage and serve.', 'https://www.themealdb.com/images/media/meals/vdwloy1713225718.jpg', 'Chicken Breasts, Oil, Hotsauce, Lemon Juice, Buns, Halloumi, Cabbage, Mayonnaise, Sour Cream, Lettuce, Red Pepper', '2, 1 tbsp, 4 tbsp, ½, 2, 250g, ¼, 2 tbsp, 4 tbsp, 4 leaves, 2', 'https://www.youtube.com/watch?v=k9Ez0bUbXKc'),
(52850, 'Chicken Couscous', 'Chicken', 'Moroccan', 'Heat olive oil in a large frying pan and cook the onion for 1-2 mins until softened. Add the chicken and fry for 7-10 mins until cooked through and onions are golden. Grate over the ginger, stir through the harissa to coat and cook for 1 min more. Tip in the apricots, chickpeas, and couscous, then pour over the stock and stir once. Cover with a lid or foil and leave for 5 mins until stock is absorbed. Fluff with a fork and scatter coriander to serve.', 'https://www.themealdb.com/images/media/meals/qxytrx1511304021.jpg', 'Olive Oil, Onion, Chicken Breast, Ginger, Harissa, Dried Apricots, Chickpeas, Couscous, Chicken Stock, Coriander', '1 tbsp, 1 chopped, 200g, pinch, 2 tbsp, 10, 220g, 200g, 200ml, Handful', 'https://www.youtube.com/watch?v=GZQGy9oscVk'),
(52934, 'Chicken Basquaise', 'Chicken', 'French', 'Preheat oven to 180C. Brown chicken joints in butter and oil, seasoning with salt and pepper; set aside. Sauté onions in the same pan for 10 mins, then add peppers and cook for 5 mins. Add chorizo, sun-dried tomatoes, and garlic for 2-3 mins. Stir in rice to coat in oil. Add tomato paste, paprika, bay leaves, thyme, stock, and wine. Bring to a simmer, press rice down, and place chicken on top. Add lemon wedges and olives. Cover and bake for 50 mins until rice is cooked and chicken juices run clear.', 'https://www.themealdb.com/images/media/meals/wruvqv1511880994.jpg', 'Chicken, Butter, Oil, Red Onions, Red Pepper, Chorizo, Sun-Dried Tomatoes, Garlic, Rice, Tomato Puree, Paprika, Bay Leaves, Thyme, Stock, Wine, Lemons, Olives', '1.5kg, 25g, 6 tbsp, 2, 3, 130g, 8, 6 cloves, 300g, drizzle, ½ tsp, 4, Handful, 350ml, 180g, 2, 100g', 'https://www.youtube.com/watch?v=emfm6TwsVhg'),
(53367, 'Chicken Fried Rice', 'Chicken', 'Chinese', 'Chop chicken into small cubes, salt, and set aside for 10 mins. Scramble eggs in a wok with oil and set aside. Cook chicken in oil for 4-5 mins and set aside. Scrape the wok. Sauté onions for 1 min, add garlic and ginger for 30 seconds, then carrots for 2 mins. Add peas. Add day-old rice, breaking up chunks. Add scallions and five-spice powder. Drizzle soy sauce and sesame oil. Stir in cooked chicken, eggs, and dark scallion parts. Cook for 1-2 mins and serve immediately.', 'https://www.themealdb.com/images/media/meals/wuyd2h1765655837.jpg', 'Chicken Thighs, Salt, Oil, Egg, Onion, Garlic, Ginger, Carrots, Peas, Jasmine Rice, Scallions, Five Spice, Soy Sauce, Sesame Oil', '1 lb, 1 tsp, 3 tbsp, 3, 2/3 cup, 2 cloves, 2 tsp, 1 large, 2/3 cup, 4 cups, 2, ½ tsp, 2.5 tbsp, 1 tsp', 'https://www.youtube.com/watch?v=mUr-7wjhHuU'),
(52879, 'Chicken Parmentier', 'Chicken', 'French', 'Topping: Boil potatoes until tender, mash with butter, cream, and egg yolks. Filling: Melt butter, fry shallots, carrots, and celery until soft, then add garlic. Pour in wine and cook for 1 min. Stir in tomato puree, tinned tomatoes, and stock; simmer for 10-15 mins until thickened. Stir in shredded chicken, olives, and parsley. Preheat oven to 180C. Place filling in an ovenproof dish, top with mash and grated Gruyere. Bake for 30-35 mins until golden brown.', 'https://www.themealdb.com/images/media/meals/uwvxpv1511557015.jpg', 'Potatoes, Butter, Double Cream, Egg Yolks, Shallots, Carrots, Celery, Garlic, Wine, Tomato Puree, Tinned Tomatoes, Chicken, Olives, Parsley, Gruyere', '1kg, 50g, 100ml, 2, 2, 2, 1, 1 clove, 150ml, 1 tbsp, 400g, 400g, 50g, Chopped, 100g', 'https://www.youtube.com/watch?v=tiG-xlmeyjg'),
(52774, 'Pad Thai', 'Chicken', 'Thai', '1. Soak rice noodles in warm water for 20 mins. 2. Heat oil, sauté garlic and chicken until cooked. 3. Push chicken to the side, scramble eggs. 4. Add noodles, beansprouts, and a sauce made of tamarind paste, fish sauce, and sugar. 5. Stir-fry everything until noodles are tender. 6. Serve topped with crushed peanuts, lime wedges, and fresh coriander.', 'https://www.themealdb.com/images/media/meals/vvpprx1487325699.jpg', 'Rice Noodles, Chicken, Garlic, Eggs, Tamarind Paste, Fish Sauce, Sugar, Beansprouts, Peanuts, Lime', '200g, 250g, 2 cloves, 2, 2 tbsp, 2 tbsp, 1 tbsp, 100g, 2 tbsp, 1', 'https://www.youtube.com/watch?v=0_fS5Z0_nEw'),
(52818, 'Chicken Enchiladas', 'Chicken', 'Mexican', '1. Poach and shred chicken. 2. Sauté onions and garlic, mix with shredded chicken and half the enchilada sauce. 3. Dip tortillas in remaining sauce, fill with chicken mixture, and roll up. 4. Place in a baking dish, pour over remaining sauce and top with plenty of cheese. 5. Bake at 180C for 20 mins until cheese is bubbly and golden. 6. Serve with sour cream and cilantro.', 'https://www.themealdb.com/images/media/meals/qtuuys1511387068.jpg', 'Chicken, Tortillas, Enchilada Sauce, Cheese, Onion, Garlic, Sour Cream, Cilantro', '500g, 8, 500ml, 200g, 1, 2 cloves, to serve, handful', 'https://www.youtube.com/watch?v=wXWFlh6Y5_M'),
(52819, 'Chicken Fajitas', 'Chicken', 'Mexican', '1. Slice chicken, peppers, and onions into strips. 2. Toss chicken in a mix of cumin, paprika, and chilli powder. 3. Heat oil in a heavy skillet and sear chicken until browned and cooked. 4. Add onions and peppers, sauté until softened but still crunchy. 5. Squeeze fresh lime juice over. 6. Serve warm with tortillas, salsa, and guacamole.', 'https://www.themealdb.com/images/media/meals/wvpsxx1468256321.jpg', 'Chicken Breast, Bell Peppers, Onion, Cumin, Paprika, Chilli Powder, Lime, Tortillas', '2, 3, 1 large, 1 tsp, 1 tsp, 1/2 tsp, 1, 6', 'https://www.youtube.com/watch?v=Id4mH_T_x6M'),
(53164, 'Spanish Chicken', 'Chicken', 'Spanish', '1. Heat oven to 190C. 2. Put all ingredients into a dish, mix and season. 3. Bake for 45 mins, stirring onions after 20 mins.', 'https://www.themealdb.com/images/media/meals/pqulvm1763282839.jpg', 'Chicken Thighs, Onion, Paprika, Lemon, Parsley, Chicken Stock, Olive Oil', '8, 3 sliced, 2 tsp, Zest and juice, Handful, 150ml, 1 tbsp', 'https://www.youtube.com/watch?v=fKqSOn5NCrk'),
(53155, 'Spanish chicken pie', 'Chicken', 'Spanish', '1. Boil and mash potatoes with paprika. 2. Fry onions, garlic, add tomatoes, chicken, peppers and olives. 3. Top with mash and bake for 15 mins.', 'https://www.themealdb.com/images/media/meals/8ovxf41763253962.jpg', 'Potatoes, Paprika, Olive Oil, Onion, Garlic, Tinned Tomatos, Chicken, Roasted pepper, Green Olives', '1 kg, 3 tsp, 2 tsp, 2 sliced, 2 cloves, 800g, 300g, 140g, Handful', ''),
(53143, 'Easy Spanish chicken', 'Chicken', 'Spanish', '1. Fry onion, chorizo and peppers in oil for 15 mins. 2. Add garlic, paprika, tomatoes, olives and beans. 3. Nestle in chicken and bake for 40 mins.', 'https://www.themealdb.com/images/media/meals/kzxflc1763194887.jpg', 'Extra Virgin Olive Oil, Onion, Chorizo, Red Pepper, Yellow Pepper, sweet smoked paprika, Garlic, Tinned Tomatos, Green Olives, Butter Beans, Chicken Thighs, Parsley', '2 tbsp, 1, 150g, 1, 1, 1 tsp, 4 cloves, 400g, 150g, 400g, 8, 1 Handfull', 'https://www.youtube.com/watch?v=EusTpzrqYK4'),
(53212, 'Thai drumsticks', 'Chicken', 'Thai', '1. Heat oven to 200C/180C fan. 2. Mix chilli sauce, orange zest/juice, garlic, curry paste and salt. 3. Coat chicken and roast for 35-40 mins.', 'https://www.themealdb.com/images/media/meals/ittake1763586925.jpg', 'sweet chilli sauce, Orange, Garlic, Thai Red Curry Paste, Chicken drumsticks', '2 tablespoons, Zest of 1, 1 clove, 1 tblsp, 8', 'https://www.youtube.com/watch?v=lv1tj9FK3f0'),
(52806, 'Tandoori chicken', 'Chicken', 'Indian', '1. Mix lemon juice, paprika and onions. 2. Slash chicken thighs and marinate for 10 mins. 3. Mix marinade ingredients, coat chicken and chill for 1hr. 4. Grill for 8 mins each side.', 'https://www.themealdb.com/images/media/meals/qptpvt1487339892.jpg', 'lemons, paprika, red onions, chicken thighs, vegetable oil, Greek yogurt, ginger, garlic clove, garam masala, ground cumin, chilli powder, turmeric', '2 Juice, 4 tsp, 2 chopped, 16, brushing, 300ml, large piece, 4, 3/4 tsp, 3/4 tsp, 1/2 tsp, 1/4 tsp', 'https://www.youtube.com/watch?v=-CKvt1KNU74'),
(52942, 'Roast Chicken', 'Chicken', 'British', '1. Preheat oven to 200C. 2. Pat chicken dry and rub with butter, salt, and pepper. 3. Stuff cavity with a halved lemon, garlic bulb, and rosemary. 4. Place in a roasting tin and cook for 1 hour and 20 mins (or 20 mins per 450g + 20 mins). 5. Baste halfway through. 6. Let the chicken rest for 15 mins before carving to keep it juicy. Serve with roast potatoes.', 'https://www.themealdb.com/images/media/meals/wvpsxx1468256321.jpg', 'Whole Chicken, Butter, Lemon, Garlic, Rosemary, Salt, Black Pepper', '1.5kg, 50g, 1, 1 bulb, 3 sprigs, pinch, pinch', 'https://www.youtube.com/watch?v=NSXhS_nZ6t0'),
(52971, 'Chicken Alfredo', 'Chicken', 'Italian', '1. Boil fettuccine in salted water. 2. Season chicken with salt/pepper and grill until cooked; slice into strips. 3. Melt butter in a pan, add heavy cream and simmer for 5 mins. 4. Whisk in grated Parmesan cheese until smooth and thick. 5. Toss the cooked pasta in the sauce. 6. Top with the sliced chicken and extra parsley. Serve immediately while creamy.', 'https://www.themealdb.com/images/media/meals/syqypv1486981727.jpg', 'Fettuccine, Chicken Breast, Butter, Heavy Cream, Parmesan Cheese, Garlic, Parsley', '400g, 2, 50g, 250ml, 100g, 1 clove, handful', 'https://www.youtube.com/watch?v=LPPf3n4-msc'),
(53028, 'Shawarma', 'Chicken', 'Egyptian', '1. Marinate chicken thighs overnight in spices, lemon and oil. 2. Grill for 4-5 mins each side until charred. 3. Serve with flatbread and yogurt sauce.', 'https://www.themealdb.com/images/media/meals/kcv6hj1598733479.jpg', 'Chicken Thighs, Coriander, Cumin, Cardamom, Cayenne Pepper, Paprika, Lemon Juice, Olive Oil, Greek Yogurt', '1 kg, 1 tbs, 1 tbs, 1 tbs, 1 tsp, 2 tsp, 2 tbs, 3 tbs, 1 cup', 'https://www.youtube.com/watch?v=3lxUIeKDgic'),
(53041, 'Grilled Chicken Salad', 'Chicken', 'American', '1. Marinate chicken in olive oil, balsamic vinegar, and dried herbs. 2. Grill until charred and cooked through; let it rest then slice. 3. In a large bowl, combine mixed greens, cherry tomatoes, cucumbers, and red onion. 4. Toss with a simple vinaigrette. 5. Top the salad with the warm sliced chicken. 6. Optional: Add feta cheese or avocado for extra richness.', 'https://www.themealdb.com/images/media/meals/pk8wtn1763758591.jpg', 'Chicken Breast, Mixed Greens, Cherry Tomatoes, Cucumber, Red Onion, Balsamic Vinegar, Olive Oil', '2, 200g, 100g, 1/2, 1/4, 2 tbsp, 3 tbsp', 'https://www.youtube.com/watch?v=I7X9LId9h6s'),
(53368, 'Sri Lankan Spicy Chicken Curry', 'Chicken', 'Sri Lankan', '1. Marinate chicken with roasted curry powder, chili powder, turmeric, salt, and lime juice for 30 mins. 2. Heat oil in a pan, add chopped onions, garlic, ginger, curry leaves, and pandan leaf (rampe). Sauté until golden. 3. Add lemongrass and cinnamon stick for aroma. 4. Add the marinated chicken and cook for 10 mins until the meat is sealed. 5. Pour in thin coconut milk (or water) and simmer until chicken is tender. 6. Finally, add thick coconut milk and cook for another 5 mins on low heat. Serve with red rice.', 'https://www.themealdb.com/images/media/meals/1529446352.jpg', 'Chicken, Roasted Curry Powder, Chili Powder, Turmeric, Cinnamon, Pandan Leaf, Curry Leaves, Coconut Milk, Ginger, Garlic', '500g, 2 tbsp, 1.5 tbsp, 1/2 tsp, 1 inch, 1 piece, 2 sprigs, 1 cup, 1 tbsp, 1 tbsp', 'https://www.youtube.com/watch?v=kYJ7tBvW_qM'),
(53369, 'Chicken Devilled (Sri Lankan Style)', 'Chicken', 'Sri Lankan', '1. Cut chicken into small cubes, season with salt and turmeric, and deep fry until golden brown. 2. In a separate wok, heat a little oil and sauté garlic, ginger, and big onion chunks. 3. Add capsicum (malo miris), tomato chunks, and dried chili flakes. 4. Stir in tomato sauce, soy sauce, and a teaspoon of sugar. 5. Add the fried chicken and toss well on high heat for 2 minutes. 6. Serve hot with fried rice or paratha.', 'https://www.themealdb.com/images/media/meals/wvpsxx1468256321.jpg', 'Chicken, Capsicum, Onions, Tomato, Tomato Sauce, Soy Sauce, Chili Flakes, Garlic, Ginger', '400g, 3, 2 large, 2, 3 tbsp, 1 tbsp, 2 tsp, 1 tbsp, 1 tbsp', 'https://www.youtube.com/watch?v=S0y_6D3W2m0'),
(53370, 'Negombo Chicken Curry (Black Curry)', 'Chicken', 'Sri Lankan', '1. Dry roast grated coconut and raw rice until dark brown, then grind into a fine paste (Kalu Pol). 2. Heat oil, add onions, garlic, ginger, and spices (cardamom, cloves). 3. Add chicken pieces and sauté well. 4. Add the ground black coconut paste and enough water. 5. Simmer on low heat until the gravy becomes thick and dark brown. 6. The slow cooking process brings out the rich oil from the coconut. Perfect with bread or hoppers.', 'https://www.themealdb.com/images/media/meals/sypxpx1515365095.jpg', 'Chicken, Grated Coconut, Raw Rice, Black Pepper, Cinnamon, Cardamom, Onion, Garlic, Curry Leaves', '500g, 4 tbsp, 1 tbsp, 1 tsp, 1 stick, 3, 1, 1 tbsp, handful', 'https://www.youtube.com/watch?v=P_8R3V2Xl7E'),
(53371, 'Sri Lankan Chicken Stew', 'Chicken', 'Sri Lankan', '1. Marinate chicken with pepper and salt. 2. Heat butter or oil, sauté onions, ginger, and garlic. 3. Add potatoes (cubed), carrots, and green chilies. 4. Add chicken and a cinnamon stick. Pour in thin coconut milk. 5. Cook until potatoes and chicken are soft. 6. Stir in thick coconut milk and a dash of vinegar for a mild tangy taste. This is a non-spicy, creamy dish perfect for children.', 'https://www.themealdb.com/images/media/meals/qxytrx1511304021.jpg', 'Chicken, Potatoes, Carrots, Green Chili, Coconut Milk, Cinnamon, Butter, Vinegar, Pepper', '500g, 2, 1, 3, 1.5 cups, 1 stick, 1 tbsp, 1 tsp, 1 tsp', 'https://www.youtube.com/watch?v=2f_LwRzX2Ew'),
(53372, 'Ceylon Roast Chicken', 'Chicken', 'Sri Lankan', '1. Make a marinade using chili powder, pepper, salt, lime juice, and a bit of oil. 2. Apply the paste thoroughly on chicken drumsticks or a whole chicken. 3. Let it marinate for 2 hours. 4. Pan-fry or oven-roast at 190C, basting with butter occasionally. 5. In the final stage, add some curry leaves to the pan for that authentic Ceylon aroma. 6. Serve with a side of spicy sambol and roast paan.', 'https://www.themealdb.com/images/media/meals/nlxald1764112200.jpg', 'Chicken Drumsticks, Chili Powder, Black Pepper, Lime, Butter, Curry Leaves, Salt', '4, 2 tbsp, 1 tsp, 1, 20g, 1 sprig, pinch', 'https://www.youtube.com/watch?v=GAnXpM6R18g'),
(53226, 'Shawarma bread', 'Side', 'Saudi Arabian', '1. Sieve flour, add baking powder, salt, sugar, oil and water. 2. Knead for 10 mins and let it rise. 3. Roll into rounds and cook on a hot pan.', 'https://www.themealdb.com/images/media/meals/i8l2fu1763742525.jpg', 'Flour, Salt, Sugar, Baking Powder, Oil, Water', '1 cup, 1 tsp, 1/2 tsp, 1/2 tsp, 1 tbsp, Splash', 'https://www.youtube.com/watch?v=ndkTbgsTCeI'),
(53218, 'Chicken Shawarma (Garlic Sauce)', 'Chicken', 'Saudi Arabian', '1. Marinate chicken slices for 10-12 hours. 2. Fry chicken in batches until seared. 3. Serve on toasted flatbread with garlic yogurt sauce and fries.', 'https://www.themealdb.com/images/media/meals/hcg6l91763596970.jpg', 'Chicken Breast, Garlic, Coriander, Cumin, Cardamom, Cayenne, Paprika, Greek Yogurt', '1kg, 2 cloves, 1 tblsp, 1 tblsp, 1 tblsp, 1 tsp, 2 tsp, 1 cup', 'https://www.youtube.com/watch?v=TROZvPHqP1g'),
(53138, 'Alfajores', 'Dessert', 'Argentinian', 'Make the Dough: Cream butter and sugar. Add egg yolks and lemon zest. Gradually mix in flour and cornstarch to form a dough. Chill for 1 hour.\r\nBake the Cookies: Roll out the dough, cut into circles, and bake at 180°C (350°F) for 12-15 minutes. Let cool.\r\nAssemble: Spread dulce de leche on one cookie, then sandwich with another. Roll the edges in coconut flakes.\r\nPro Tips:\r\n\r\nChill the dough before rolling it out to make it easier to handle and to prevent the cookies from spreading too much while baking.\r\nDip the alfajores in melted chocolate and let them set on a wire rack for an extra decadent treat.', 'https://www.themealdb.com/images/media/meals/a4kgf21763075288.jpg', 'All purpose flour, Cornstarch, Butter, Sugar, Egg Yolks, Lemon Zest, Dulce de leche, Desiccated Coconut', '300g, 200g, 200g, 100g, 2, 1 teaspoon, To taste, Sprinkling', 'https://www.youtube.com/watch?v=9WR40GHpsyo'),
(53321, 'Vanilla alfajores', 'Dessert', 'Uruguayan', 'For the sandwich cookie cream the soft butter for about a minute, then add the sugar and cream for another two minutes. Incorporate the egg fully before mixing in the egg yolk. Once everything is nicely combined, add all remaining ingredients and mix one more time. Form dough into a ball and wrap in plastic wrap. Chill for at least half an hour or overnight.\r\n\r\n2\r\nPreheat oven to 180 degrees Celsius and line two baking sheets with parchment paper.\r\n\r\n3\r\nDivide dough in half, put one back in the fridge and roll out the other thickly on a lightly floured surface. Cut out cookies with either the bottom of a glass or a cookie cutter around 6cm in diameter. Repeat with all the dough.\r\n\r\n4\r\nBake for about 8-10min, the cookies will look very pale. Let cool off before filling half with each a teaspoon of dulce de leche. Place other half of cookies on top and roll the sides of each cookie in the coconut flakes (it helps if the dulce de leche was pressed down to the sides of the cookie). Enjoy.', 'https://www.themealdb.com/images/media/meals/3wnyvh1764373818.jpg', 'Dulce de leche, Coconut Flakes, Butter, Sugar, Egg, Egg Yolks, Cornstarch, All purpose flour, Baking Powder, Vanilla Extract', '150g, 50g, 100g, 100g, 1, 1, 200g, 100g, 1 tsp, 1 tsp', 'https://www.youtube.com/watch?v=9MncGG2cH_g'),
(53320, 'Chocolate alfajores', 'Dessert', 'Uruguayan', 'For the cookies cream the butter with the sugar for a few minutes. Then add the egg and honey and mix well. Add flour, cornstarch, cocoa, baking soda and baking powder and mix until you get a dough. Wrap in plastic wrap and chill for at least half an hour or overnight.\r\n\r\n2\r\nLine two baking sheets with parchment paper, preheat oven to 200 degrees Celsius.\r\n\r\n3\r\nDivide dough into two parts, put one part back in the fridge before using. Roll out second part to about 2 millimeters and cut out round cookies with 5-6 centimeters in diameter. This can be done with a cookie cutter or glass. You should get 30 cookies in total or even more, I get about 40. Bake one baking sheet at the time for about 8-10min. Let cookies cool.\r\n\r\n4\r\nFor the filling look for two cookies of the same size and place about one teaspoon of dulce de leche onto the bottom one before sandwiching together.\r\n\r\n5\r\nChop semi-sweet chocolate and melt with butter and orange zest on low heat. Dunk each sandwich cookie into the chocolate and let cool off on parchment paper before serving.', 'https://www.themealdb.com/images/media/meals/k9o0xr1764373018.jpg', 'Butter, Sugar, Egg, Honey, All purpose flour, Cornstarch, Unsweetened Cocoa, Baking Powder, Dulce de leche, Milk Chocolate, Orange', '150g, 70g, 1, 25g, 175g, 80g, 30g, 1 tsp, 400g, 500g, Zest of 1', 'https://www.youtube.com/watch?v=ucBoYab5tXY'),
(53049, 'Apam balik', 'Dessert', 'Malaysian', 'Mix milk, oil and egg together. Sift flour, baking powder and salt into the mixture. Stir well until all ingredients are combined evenly.\r\n\r\nSpread some batter onto the pan. Spread a thin layer of batter to the side of the pan. Cover the pan for 30-60 seconds until small air bubbles appear.\r\n\r\nAdd butter, cream corn, crushed peanuts and sugar onto the pancake. Fold the pancake into half once the bottom surface is browned.\r\n\r\nCut into wedges and best eaten when it is warm.', 'https://www.themealdb.com/images/media/meals/adxcbq1619787919.jpg', 'Milk, Oil, Eggs, Flour, Baking Powder, Salt, Unsalted Butter, Sugar, Peanut Butter', '200ml, 60ml, 2, 1600g, 3 tsp, 1/2 tsp, 25g, 45g, 3 tbs', 'https://www.youtube.com/watch?v=6R8ffRRJcrg');
INSERT INTO `recipes` (`id`, `name`, `category`, `area`, `instructions`, `thumbnail`, `all_ingredients`, `all_measures`, `youtube`) VALUES
(52768, 'Apple Frangipan Tart', 'Dessert', 'British', 'Preheat the oven to 200C/180C Fan/Gas 6.\r\nPut the biscuits in a large re-sealable freezer bag and bash with a rolling pin into fine crumbs. Melt the butter in a small pan, then add the biscuit crumbs and stir until coated with butter. Tip into the tart tin and, using the back of a spoon, press over the base and sides of the tin to give an even layer. Chill in the fridge while you make the filling.\r\nCream together the butter and sugar until light and fluffy. Mix in the eggs, then add the ground almonds and almond extract and blend until well combined.\r\nPeel the apples, and cut thin slices. Arrange the slices over the biscuit base. Spread the frangipane filling evenly on top. Level the surface and sprinkle with the flaked almonds.\r\nBake for 20-25 minutes until golden-brown and set.\r\nRemove from the oven and leave to cool for 15 minutes. Remove the sides of the tin. Transfer the tart to a serving plate. Serve warm.', 'https://www.themealdb.com/images/media/meals/wxywrq1468235067.jpg', 'digestive biscuits, butter, Bramley apples, Salted Butter, caster sugar, free-range eggs, ground almonds, almond extract, flaked almonds', '175g, 75g, 200g, 75g, 75g, 2, 75g, 1 tsp, 50g', 'https://www.youtube.com/watch?v=rp8Slv4INLk'),
(53277, 'Lamb & apricot meatballs', 'Lamb', 'Turkish', 'Heat 2 tsp oil in a pan and soften the onions for 5 mins. Add the garlic and spices and cook for a few mins more. Spoon half the onion mixture into a bowl and set aside to cool. Add the tomatoes, sugar and seasoning to the remaining onions in the pan and simmer for about 10 mins until reduced. Meanwhile, add the mint, lamb, apricots and breadcrumbs to the cooled onions, season and mix well with your hands. Shape into little meatballs. Heat the rest of the oil in a non-stick pan and fry the meatballs until golden. Stir in the sauce with a splash of water and gently cook everything for a few mins until the meatballs are cooked through. Serve with pitta bread.', 'https://www.themealdb.com/images/media/meals/72fgzj1764109947.jpg', 'Olive Oil, Red Onions, Garlic, Ground Cumin, Ground Coriander, Tinned Tomatos, Sugar, Mint, Lamb Mince, Dried Apricots, Breadcrumbs, Pita Bread', '2 tbsp, 2 chopped, 4 Cloves, 2 tsp, 2 tsp, 400g, 1/2 tsp, 10g, 500g, 8, 50g, To serve', 'https://www.youtube.com/watch?v=o0UbzRZw-GQ'),
(53276, 'Apricot & Turkish delight mess', 'Dessert', 'Turkish', 'Place the mascarpone, yogurt, sugar and orange flower water into a large bowl and whisk until thickened. Fold the remaining ingredients through (meringue, apricots, Turkish delight, almonds, mint), then divide the mix between 2 dessert glasses or bowls and decorate with extra mint.', 'https://www.themealdb.com/images/media/meals/p277uc1764109195.jpg', 'Mascarpone, Greek Yogurt, Icing Sugar, Orange Blossom Water, Meringue Nests, Apricot, Turkish Delight, Almonds, Mint', '100g, 50g, 25g, 2 tbsp, 1, 3, 2 pieces, 25g, 4', ''),
(53127, 'Authentic Norwegian Kransekake', 'Dessert', 'Norwegian', 'Grind almonds in an almond grinder or food processor. Mix almonds and powdered sugar together in a large mixing bowl. Add three of the egg whites and knead the dough together with your hands until it comes together in a ball. Wrap in cling film and leave in the fridge for at least an hour. Grease the kransekake forms thoroughly. Preheat oven to 210C. Divide the dough into six sections. Roll into long sausages about as thick as your index finger. Fill the forms with the dough sausages, pinching the ends together to make rings. Bake for about 10–12 minutes, until the tops are golden brown.', 'https://www.themealdb.com/images/media/meals/yk78uc1763075719.jpg', 'Almonds, Egg White, Powdered Sugar, Lemon Juice', '3 Cups, 4, 4 cups, 1/2 teaspoon', 'https://www.youtube.com/watch?v=fE85ioKE7ew'),
(52855, 'Banana Pancakes', 'Dessert', 'American', 'In a bowl, mash the banana with a fork until it resembles a thick purée. Stir in the eggs, baking powder and vanilla. Heat a large non-stick frying pan or pancake pan over a medium heat and brush with half the oil. Using half the batter, spoon two pancakes into the pan, cook for 1-2 mins each side, then tip onto a plate. Repeat the process with the remaining oil and batter. Top the pancakes with the pecans and raspberries.', 'https://www.themealdb.com/images/media/meals/sywswr1511383814.jpg', 'Banana, Eggs, Baking Powder, Vanilla Extract, Oil, Pecan Nuts, Raspberries', '1 large, 2 medium, pinch, sprinkling, 1 tsp, 25g, 125g', 'https://www.youtube.com/watch?v=kSKtb2Sv-_U'),
(52894, 'Battenberg Cake', 'Dessert', 'British', 'Heat oven to 180C/160C fan/gas 4 and line the base and sides of a 20cm square tin with baking parchment (the easiest way is to cross 2 x 20cm-long strips over the base). To make the almond sponge, put the butter, sugar, flour, ground almonds, baking powder, eggs, vanilla and almond extract in a large bowl. Beat with an electric whisk until the mix comes together smoothly. Scrape into the tin, spreading to the corners, and bake for 25-30 mins – when you poke in a skewer, it should come out clean. Cool in the tin for 10 mins, then transfer to a wire rack to finish cooling while you make the second sponge.\r\nFor the pink sponge, line the tin as above. Mix all the ingredients together as above, but don\'t add the almond extract. Fold in some pink food colouring. Then scrape it all into the tin and bake as before. Cool.\r\nTo assemble, heat the jam in a small pan until runny, then sieve. Barely trim two opposite edges from the almond sponge, then well trim a third edge. Roughly measure the height of the sponge, then cutting from the well-trimmed edge, use a ruler to help you cut 4 slices each the same width as the sponge height. Discard or nibble leftover sponge. Repeat with pink cake.\r\nTake 2 x almond slices and 2 x pink slices and trim so they are all the same length. Roll out one marzipan block on a surface lightly dusted with icing sugar to just over 20cm wide, then keep rolling lengthways until the marzipan is roughly 0.5cm thick. Brush with apricot jam, then lay a pink and an almond slice side by side at one end of the marzipan, brushing jam in between to stick sponges, and leaving 4cm clear marzipan at the end. Brush more jam on top of the sponges, then sandwich remaining 2 slices on top, alternating colours to give a checkerboard effect. Trim the marzipan to the length of the cakes.\r\nCarefully lift up the marzipan and smooth over the cake with your hands, but leave a small marzipan fold along the bottom edge before you stick it to the first side. Trim opposite side to match size of fold, then crimp edges using fingers and thumb (or, more simply, press with prongs of fork). If you like, mark the 10 slices using the prongs of a fork.\r\nAssemble second Battenberg and keep in an airtight box or well wrapped in cling film for up to 3 days. Can be frozen for up to a month.', 'https://www.themealdb.com/images/media/meals/ywwrsp1511720277.jpg', 'Butter, Caster Sugar, Self-raising Flour, Almonds, Baking Powder, Eggs, Vanilla Extract, Almond Extract, Pink Food Colouring, Apricot, Marzipan, Icing Sugar', '175g, 175g, 140g, 50g, 0.5 tsp, 3 Medium, 0.5 tsp, 0.25 tsp, 0.5 tsp, 200g, 1kg, Dusting', 'https://www.youtube.com/watch?v=aB41Q7kDZQ0'),
(53316, 'Beetroot pancakes', 'Dessert', 'Ukrainian', 'step 1\r\nPut the beetroot in a jug with the milk and blend with a stick blender until smooth. Pour into a bowl with the rest of the pancake ingredients and whisk until smooth and vibrant purple.\r\n\r\nstep 2\r\nPut a small knob of butter in a large non-stick frying pan and heat over a medium-low heat until melted and foamy. Now create 3 or 4 pancakes each made from 2 tbsp of the batter. Cook for 2-3 mins then flip over and cook for a further minute until cooked through. Repeat with any remaining batter. Heat oven to lowest setting and keep the pancakes warm in there until needed.\r\n\r\nstep 3\r\nServe with your favourite pancake toppings or make a simple compote by simmering frozen berries in with 1 tbsp blackcurrant jam until bubbling and syrupy (about 5-10 mins). In a small bowl stir together the remaining jam and the yogurt. Stack the cooked pancakes with the yogurt and pour the warm berry compote over the top.', 'https://www.themealdb.com/images/media/meals/xlqqhw1764369924.jpg', 'Beetroot, Milk, Self-raising Flour, Baking Powder, Maple Syrup, Vanilla Extract, Egg, Butter, Frozen Mixed Berries, Blackcurrant Jam, Greek Yogurt', '3, 50 ml, 200g, 1 tsp, 2 tablespoons, 0.5 tsp, 3, 25g, 200g, 2 tablespoons, 100g', 'https://www.youtube.com/watch?v=HzQT0rHKCWM'),
(52891, 'Blackberry Fool', 'Dessert', 'British', 'For the biscuits, preheat the oven to 200C/180C (fan)/Gas 6 and line two large baking trays with baking parchment. Scatter the nuts over a baking tray and roast in the oven for 6-8 minutes, or until golden-brown. Watch them carefully so that they don\'t have a chance to burn. Remove from the oven, tip onto a board and leave to cool.\r\nPut the butter and sugar in a large bowl and beat with a wooden spoon until light and creamy. Roughly chop the cooled nuts and add to the creamed butter and sugar, along with the lemon zest, flour and baking powder. Stir well until the mixture comes together and forms a ball – you may need to use your hands.\r\nDivide the biscuit dough into 24 even pieces and roll into small balls. Place the balls the prepared baking trays, spaced well apart to allow for spreading.\r\nPress the biscuits to flatten to around 1cm/0.5in thick. Bake the biscuits, one tray at a time, for 12 minutes or until very pale golden-brown. Leave to cool on the trays. They will be very soft when you take them out of the oven, but will crisp as they cool.\r\nStore in an airtight tin and eat within five days.\r\nFor the fool, rinse the blackberries in a colander to wash away any dust or dirt. Put the blackberries in a non-stick saucepan and sprinkle over the caster sugar.\r\nStir in the lemon juice and heat gently for two minutes, or until the blackberries begin to soften and release their juices. Remove and reserve 12 blackberries for decoration and continue cooking the rest.\r\nSimmer the blackberries very gently for 15 minutes, stirring regularly until very soft and squidgy. Remove from the heat and press the berries and juice through a sieve over a bowl, using the bottom of a ladle to help you extract as much of the purée as possible. Leave the purée to cool and discard the seeds. You should end up with around 325ml/11fl oz of purée.\r\nPut the cream and yoghurt in a large bowl and whip with an electric whisk until soft peaks form when the whisk is removed from the bowl – the acidity of the fruit will thicken the cream further, so don\'t take it too far.\r\nWhen the purée is completely cold, adjust the sweetness to taste by adding more sugar if needed. Pour it into the bowl with the whipped cream and yoghurt and stir just once or twice until very lightly combined.\r\nSpoon the blackberry fool into individual wide, glass dishes – or one large, single bowl. It should look quite marbled, so don\'t over-stir it. Scatter a few tiny mint leaves on top and decorate with the reserved blackberries. Sprinkle with a little sugar if you like and serve with the hazelnut biscuits.', 'https://www.themealdb.com/images/media/meals/rpvptu1511641092.jpg', 'Hazlenuts, Butter, Caster Sugar, Lemon, Plain Flour, Baking Powder, Blackberries, Sugar, Caster Sugar, Lemon Juice, Double Cream, Yogurt, Mint', '50g, 125g, 150g, Grated, 150g, 0.5 tsp, 600g, 75g, 2 tbs, 1 tbs, 300ml, 100ml, Garnish with', 'https://www.youtube.com/watch?v=kniRGjDLFrQ'),
(52862, 'Peach & Blueberry Grunt', 'Dessert', 'American', 'Heat oven to 190C/170C fan/gas 5. Butter a wide shallow ovenproof dish. Blend the cornflour with the orange zest and juice, and put in a large pan with the sugar. Halve, stone and slice the peaches and add to the pan. Bring slowly to the boil, stirring gently until the sauce is shiny and thickened, about 3-4 mins. Remove from the heat, stir in the blueberries and tip into the prepared dish.\r\nTip the flour into a mixing bowl and add the 50g butter. Rub the butter into the flour until it resembles fine breadcrumbs, then stir in half the sugar. Mix the remaining sugar with the cinnamon and set aside.\r\nAdd the milk to the dry ingredients and mix to a soft dough. Turn out onto a lightly floured surface and knead briefly. Roll out to an oblong roughly 16 x 24cm. Brush with melted butter and sprinkle evenly with the spicy sugar. Roll up from one long side and cut into 12 slices. Arrange around the top of the dish, leaving the centre uncovered.\r\nBake for 20-25 mins, until the topping is crisp and golden. Serve warm.', 'https://www.themealdb.com/images/media/meals/ssxvup1511387476.jpg', 'Corn Flour, Orange, Orange, Caster Sugar, Peaches, Blueberries, Self-raising Flour, Butter, Muscovado Sugar, Cinnamon, Milk', '1 tsp, Juice of 2, Zest of 1, 2 tbs, 6, 250g, 200g, 50g, 100g, 1 tsp, 6 tblsp', 'https://www.youtube.com/watch?v=SNeO28BCpsc'),
(53100, 'Blueberry & lemon friands', 'Dessert', 'Australian', 'step 1\r\nPreheat the oven to fan 180C/conventional 200C/gas 6. Generously butter six non-stick friand or muffin tins. Melt the butter and set aside to cool.\r\n\r\nstep 2\r\nSift the icing sugar and flour into a bowl. Add the almonds and mix everything between your fingers.\r\n\r\nstep 3\r\nWhisk the egg whites in another bowl until they form a light, floppy foam. Make a well in the centre of the dry ingredients, tip in the egg whites and lemon rind, then lightly stir in the butter to form a soft batter.\r\n\r\nstep 4\r\nDivide the batter among the tins, a large serving spoon is perfect for this job. Sprinkle a handful of blueberries over each cake and bake for 15-20 minutes until just firm to the touch and golden brown.\r\n\r\nstep 5\r\nCool in the tins for 5 minutes, then turn out and cool on a wire rack. To serve, dust lightly with icing sugar.', 'https://www.themealdb.com/images/media/meals/e756bf1761848342.jpg', 'Unsalted Butter, Icing Sugar, Flour, Almonds, Egg White, Unwaxed Lemon, Blackberries', '100g, 125g, 25g, 85g, 3, 1, 85g', 'https://www.youtube.com/watch?v=7tq5JvO88E0'),
(52897, 'Carrot Cake', 'Dessert', 'British', 'For the carrot cake, preheat the oven to 160C/325F/Gas 3. Grease and line a 26cm/10in springform cake tin.\r\nMix all of the ingredients for the carrot cake, except the carrots and walnuts, together in a bowl until well combined. Stir in the carrots and walnuts.\r\nSpoon the mixture into the cake tin and bake for 1 hour 15 minutes, or until a skewer inserted into the middle comes out clean. Remove the cake from the oven and set aside to cool for 10 minutes, then carefully remove the cake from the tin and set aside to cool completely on a cooling rack.\r\nMeanwhile, for the icing, beat the cream cheese, caster sugar and butter together in a bowl until fluffy. Spread the icing over the top of the cake with a palette knife.', 'https://www.themealdb.com/images/media/meals/vrspxv1511722107.jpg', 'Vegetable Oil, Plain Flour, Bicarbonate Of Soda, Sugar, Eggs, Salt, Cinnamon, Carrots, Walnuts, Cream Cheese, Caster Sugar, Butter', '450ml, 400g, 2 tsp, 550ml, 5, 0.5 tsp, 2 tsp, 500g grated, 150g, 200g, 150g, 100g', 'https://www.youtube.com/watch?v=asjZ7iTrGKA'),
(52917, 'White chocolate creme brulee', 'Dessert', 'French', 'Heat the cream, chocolate and vanilla pod in a pan until the chocolate has melted. Take off the heat and allow to infuse for 10 mins, scraping the pod seeds into the cream. If using the vanilla extract, add straight away. Heat oven to 160C/fan 140C/gas 3.\r\nBeat yolks and sugar until pale. stir in the chocolate cream. Strain into a jug and pour into ramekins. Place in a deep roasting tray and pour boiling water halfway up the sides. Bake for 15-20 mins until just set with a wobbly centre. Chill in the fridge for at least 4 hrs.\r\nTo serve, sprinkle some sugar on top of the brûlées and caramelise with a blowtorch or briefly under a hot grill. Leave caramel to harden, then serve.', 'https://www.themealdb.com/images/media/meals/uryqru1511798039.jpg', 'Double Cream, White Chocolate Chips, Vanilla, Egg Yolks, Caster Sugar, Caster Sugar', '568ml, 100g, Pod of, 6, 2 tbs, Top', 'https://www.youtube.com/watch?v=LmJ0lsPLHDc'),
(52970, 'Tunisian Orange Cake', 'Dessert', 'Tunisian', 'Preheat oven to 190 C / Gas 5. Grease a 23cm round springform tin.\r\nCut off the hard bits from the top and bottom of the orange. Slice the orange and remove all seeds. Puree the orange with its peel in a food processor. Add one third of the sugar and the olive oil and continue to mix until well combined.\r\nSieve together flour and baking powder.\r\nBeat the eggs and the remaining sugar with an electric hand mixer for at least five minutes until very fluffy. Fold in half of the flour mixture, then the orange and the vanilla, then fold in the remaining flour. Mix well but not for too long.\r\nPour cake mixture into prepared tin and smooth out. Bake in preheated oven for 20 minutes. Reduce the oven temperature to 160 C / Gas 2 and bake again for 30 minutes Bake until the cake is golden brown and a skewer comes out clean. Cool on a wire cake rack.', 'https://www.themealdb.com/images/media/meals/y4jpgq1560459207.jpg', 'Orange, Caster Sugar, Olive Oil, Flour, Baking Powder, Eggs, Vanilla Extract', '1 large, 300g, 75 ml, 280g, 1 tbs, 4 large, 2 tsp', 'https://www.youtube.com/watch?v=rCUxg866Ea4'),
(52889, 'Summer Pudding', 'Dessert', 'British', 'Bring out the juices: Wash fruit and gently dry on kitchen paper – keep strawberries separate. Put sugar and 3 tbsp water into a large pan. Gently heat until sugar dissolves – stir a few times. Bring to a boil for 1 min, then tip in the fruit (not strawberries). Cook for 3 mins over a low heat, stirring 2-3 times. The fruit will be softened, mostly intact and surrounded by dark red juice. Put a sieve over a bowl and tip in the fruit and juice.\r\nLine the bowl with cling film and prepare the bread: Line the 1.25-litre basin with cling film as this will help you to turn out the pudding. Overlap two pieces of cling film in the middle of the bowl as it’s easier than trying to get one sheet to stick to all of the curves. Let the edges overhang by about 15cm. Cut the crusts off the bread. Cut 4 pieces of bread in half, a little on an angle, to give 2 lopsided rectangles per piece. Cut 2 slices into 4 triangles each and leave the final piece whole.\r\nBuild the pud: Dip the whole piece of bread into the juice for a few secs just to coat. Push this into the bottom of the basin. Now dip the wonky rectangular pieces one at a time and press around the basin’s sides so that they fit together neatly, alternately placing wide and narrow ends up. If you can’t quite fit the last piece of bread in it doesn’t matter, just trim into a triangle, dip in juice and slot in. Now spoon in the softened fruit, adding the strawberries here and there as you go.\r\nLet flavours mingle then serve: Dip the bread triangles in juice and place on top – trim off overhang with scissors. Keep leftover juice for later. Bring cling film up and loosely seal. Put a side plate on top and weight down with cans. Chill for 6 hrs or overnight. To serve, open out cling film then put a serving plate upside-down on top and flip over. serve with leftover juice, any extra berries and cream.', 'https://www.themealdb.com/images/media/meals/rsqwus1511640214.jpg', 'Strawberries, Blackberries, Redcurrants, Raspberries, Caster Sugar, Bread', '300g, 250g, 100g, 500g, 175g, 7 Slices', 'https://www.youtube.com/watch?v=akJIO6UhXtA'),
(53082, 'Strawberries Romanoff', 'Dessert', 'Russian', 'In a medium bowl, combine hulled and quartered strawberries, 4 Tbsp sugar and 4 Tbsp liqueur, stir to combine then cover and refrigerate at least 1 hour and up to 2 hours, stirring once or twice. Just before serving, in a large mixing bowl, combine 1 cup cold heavy cream and 1/4 cup powdered sugar, and beat with an electric mixer until stiff peaks form. Using a spatula, fold in 1/4 cup sour cream just until well blended. To serve, stir strawberries then divide between 6 serving glasses or bowls. Spoon cream over strawberries, dividing evenly.', 'https://www.themealdb.com/images/media/meals/oe8rg51699014028.jpg', 'Strawberries, Sugar, Grand Marnier, Cream, Sour Cream', '2 pint, 4 tbs, 4 tbs, 1 cup, 1/4 cup', 'https://www.youtube.com/watch?v=ybWHc4Vi-xU'),
(53163, 'Spanish fig & almond balls', 'Dessert', 'Spanish', 'Whizz the almonds in a food processor until most are finely chopped, then tip into a large bowl. Roughly chop the figs, then whizz to a smooth sticky paste. Scrape onto the almonds then, using your hands, mix together well with the dried fruit, brandy, honey and cloves. Divide the mixture into 6 and roll into balls. Tip the sesame seeds onto a tray, then roll the balls in them until covered. Leave the fig balls to dry for a week before packaging.', 'https://www.themealdb.com/images/media/meals/si2rty1763282314.jpg', 'Almonds, Figs, Dried Apricots, Dried cranberries, Brandy, Clear Honey, Cloves, Sesame Seed', '100g, 500g, 85g, 50g, 1 tablespoon, 1 tblsp, 1 teaspoon, 100g', ''),
(53054, 'Seri muka kuih', 'Dessert', 'Malaysian', 'Soak glutinous rice with water for at least 1.5 hours prior to using. Drain.\r\nPrepare a 9-inch round or square cake pan and spray with cooking spray or line with plastic wrap.\r\nMix coconut milk, water, salt and the rice. Pour it into cake pan, topped with the pandan knots.\r\nSteam for 30 minutes.\r\nAfter 30 minutes, fluff up the rice and remove pandan knots. Then, using a greased spatula, flatten the steamed rice. Make sure there are no holes/air bubbles and gaps in the rice, especially the sides.\r\nSteam for another 10 minutes.\r\n\r\nCombine pandan juice, coconut milk, all purpose flour, cornflour, and sugar. Mix well.\r\nAdd eggs and whisk well then strain into a medium sized metal bowl or pot.\r\nPlace pandan mixture over simmering water (double boiler or bain-marie)\r\nStir continuously and cook till custard starts to thicken. (15 minutes)\r\nPour pandan custard into glutinous rice layer, give it a little tap (for air bubbles) and continue to steam for 30 minutes.\r\nRemove kuih seri muka from the steamer and allow to cool completely before cutting into rectangles or diamond shapes.', 'https://www.themealdb.com/images/media/meals/6ut2og1619790195.jpg', 'Rice, Coconut Milk, Water, Salt, Corn Flour, Flour, Eggs, Coconut Cream, Sugar', '400g, 150ml, 100ml, 1 tsp, 5 tbs, 3 tbs, 3, 200ml, 140g', 'https://www.youtube.com/watch?v=_NJtCfqgaBo'),
(53337, 'Saskatoon Pie', 'Dessert', 'Canadian', 'To make the pastry, place the flour and salt in a large bowl. Mix well. Add the cubes of butter and shortening and mix them in just until it looks like coarse oatmeal with some pea-sized bits remaining. Place the egg in a 2-cup measure and beat it with a fork. Beat in the vinegar and just enough ice-cold water to bring it to the 1-cup mark. Stir this into the flour mixture, just until the dough clings together. Try not to overmix it.\r\nOn a lightly floured surface, gather the dough into a ball and divide it into 5 evenly sized portions. Shape each portion into a disc and wrap tightly in plastic. Chill 2 of these discs for 1 hour. Freeze the other 3 in a resealable freezer bag for future use. Preheat the oven to 350°F. Line a baking sheet with aluminum foil to catch drippings.\r\nOn a lightly floured surface, roll out 1 disc of pastry into a 12-inch circle. Place it in the bottom of a 9-inch pie plate. To make the filling, place the saskatoon berries in a large bowl and stir in the 0.5 cup sugar and the cornstarch until well combined. Pour the berry mixture into the bottom of the pie. Dot with the butter. Roll out the top crust and cut into 6 wide strips. Weave the pastry strips, going over and under. Bake for about 90 – 100 minutes, until it\'s golden brown and bubbling.', 'https://www.themealdb.com/images/media/meals/5xdrkw1764444472.jpg', 'All purpose flour, Salt, Unsalted Butter, Vegetable Shortening, Egg, Vinegar, Water, Saskatoon Berries, Sugar, Sugar, Cornstarch, Unsalted Butter, Egg, Water', '6 cups, 2 tsp, 1 cup, 1 cup, 1 large, 1 tablespoon, Splash, 5 Cups, 1/2 cup, 1 tablespoon, 3 tablespoons, 2 tablespoons, 1 beaten, 1 tablespoon', 'https://www.youtube.com/watch?v=wla0ijWVLCs'),
(52833, 'Salted Caramel Cheescake', 'Dessert', 'American', '1) Blitz the biscuits and the pretzels in a food processor and mix the biscuits with the melted butter. Spread on the bottom of an 8\"/20cm Deep Springform Tin and press down firmly.\r\n2) Using an electric mixer, whisk together the cream cheese, vanilla, and icing sugar until smooth and then add the caramel and whisk again until smooth.\r\n3) Pour in the double cream & Salt flakes and continue to whisk for a couple of minutes until its very thick and mousse like. If you don\'t mix it enough it will not set well enough, but don\'t get impatient and whisk it really quick because that\'ll make it split! Spread over the biscuit base and leave to set in the fridge overnight.\r\n4) Remove the Cheesecake from the tin carefully and decorate with spare caramel, Toffee Popcorn and more Pretzels!', 'https://www.themealdb.com/images/media/meals/xqrwyr1511133646.jpg', 'Digestive Biscuits, Pretzels, Butter, Cream Cheese, Vanilla Extract, Icing Sugar, Caramel, Sea Salt, Double Cream, Caramel Sauce, Toffee Popcorn, Pretzels', '250g, 75g, 135g, 450g, 1tsp, 100g, 150g, 1tsp, 300ml, drizzle, Top, Top', 'https://www.youtube.com/watch?v=q5dQp3qpmI4'),
(53303, 'Raspberry mousse', 'Dessert', 'Polish', 'step 1\r\nPut the gelatine leaves in a bowl, cover with warm water and leave to soak for 5 mins. Drain and squeeze out any excess water.\r\nstep 2\r\nTip the raspberries into a pan over a medium-low heat along with the sugar and lemon juice. Cook for 5-6 mins until the berries have completely broken down. Push the mixture through a sieve set over a bowl, discarding the seeds. Stir in the gelatine leaves until dissolved. Set aside to cool for 15 mins.\r\nstep 3\r\nWhip the cream to soft peaks using an electric whisk, then gently fold this into the raspberry mixture. Spoon into the ramekins or moulds and chill overnight, or for at least 6 hrs. Serve with raspberries scattered over the top.', 'https://www.themealdb.com/images/media/meals/v5jrnn1764362830.jpg', 'Gelatine Leafs, Raspberries, Caster Sugar, Lemon, Whipping Cream', '2, 350g, 60g, Juice of 1, 500ml', 'https://www.youtube.com/watch?v=YbFsvvwcSCw'),
(53323, 'Postre Chajá', 'Dessert', 'Uruguayan', 'For the sponge cake preheat oven to 180 degrees Celsius and prepare cake pan. Divide the eggs into white and yolks. Beat the egg whites until soft peaks form. Beat the egg yolks with the sugar until creamy. Gently fold in flour and cornstarch with egg whites. Bake for 25-35 minutes. For the meringue, beat egg white with salt and sugar until glossy. Dry for 45min at 100 degrees Celsius. For the filling, beat heavy cream, vanilla and sugar. Layer the cake with peach juice, whipped cream, peaches and dulce de leche. Crush the meringue and pat around the sides. Serve immediately.', 'https://www.themealdb.com/images/media/meals/wii0591764375062.jpg', 'Egg, Sugar, Salt, All purpose flour, Cornstarch, Egg White, Sugar, Dulce de leche, Heavy Cream, Vanilla Extract, Sugar, Peaches, Peach Juice, Cornstarch', '5, 100g, Pinch, 75g, 30g, 1, 50g, 200g, 400g, 1 tsp, 40g, 500g, 50 ml, 1 tsp', 'https://www.youtube.com/watch?v=-O6MsNm39Yw'),
(53333, 'Passion fruit mousse', 'Dessert', 'Venezulan', 'Add gelatin and 1/4 cup water to bowl; let sit for 5 minutes. In saucepan, stir passion fruit pulp, sugar and gelatin. Cook until smooth but do not boil. Cool and stir in condensed milk. Beat egg whites until stiff. Fold 1/3 of egg whites into passion fruit mixture, then gently fold in the rest. Divide into cups and refrigerate for 2 hours. Garnish with mint.', 'https://www.themealdb.com/images/media/meals/gkcdpl1764441325.jpg', 'Unflavoured Gelatin, Passion Fruit Pulp, Sugar, Condensed Milk, Egg White, Mint', '1.5 tbsp, 1, 1 cup, 1 Can, 6, 1 Sprig', 'https://www.youtube.com/watch?v=x5SRhOq3vfs'),
(52854, 'Pancakes', 'Dessert', 'American', 'Whisk flour, eggs, milk, 1 tbsp oil and salt into a smooth batter. Rest for 30 mins. Heat a frying pan with oiled paper. Cook pancakes for 1 min on each side until golden. Serve with lemon and sugar.', 'https://www.themealdb.com/images/media/meals/rwuyqx1511383174.jpg', 'Flour, Eggs, Milk, Sunflower Oil, Sugar, Raspberries, Blueberries', '100g, 2 large, 300ml, 1 tbls, to serve, to serve, to serve', 'https://www.youtube.com/watch?v=LWuuCndtJr0'),
(53080, 'Blini Pancakes', 'Side', 'Russian', 'Whisk buckwheat flour, all-purpose flour, salt, and yeast. Pour in warm milk and whisk until smooth. Let rise for 1 hour. Stir in melted butter and egg yolk. Fold in stiffly whisked egg white. Let stand for 20 minutes. Fry small dollops of batter in butter for 1 minute until bubbles form, then flip for 30 seconds.', 'https://www.themealdb.com/images/media/meals/0206h11699013358.jpg', 'Buckwheat, Flour, Salt, Yeast, Milk, Butter, Egg', '1/2 cup, 2/3 Cup, 1/2 tsp, 1 tsp, 1 cup, 2 tbs, 1 Seperated', 'https://www.youtube.com/watch?v=GsB8ZI5vREA'),
(53331, 'Oatmeal pancakes', 'Breakfast', 'Venezulan', 'Beat all ingredients together and let stand for 10 minutes. Grease a pan with butter and pour mixture. When bubbles appear, flip with a spatula. Cook over medium-low heat. Serve with caramel and strawberries.', 'https://www.themealdb.com/images/media/meals/c400ok1764439058.jpg', 'Egg, Milk, Sugar, Baking Powder, Salt, Vanilla Extract, Ground Oats, Butter, Sugar Syrup, Strawberries', '1 medium, 80 ml, 1 tablespoon, 1 tsp, Pinch, 1 dash, 150g, 150g, 1 tablespoon, 3', 'https://www.youtube.com/watch?v=kkrRFWN4LG4'),
(53076, 'Bread omelette', 'Breakfast', 'Indian', 'Make and enjoy', 'https://www.themealdb.com/images/media/meals/hqaejl1695738653.jpg', 'Bread, Egg, Salt', '2, 2, 0.5', ''),
(52965, 'Breakfast Potatoes', 'Breakfast', 'Canadian', 'Before you do anything, freeze your bacon slices that way when you\'re ready to prep, it\'ll be so much easier to chop!\r\nWash the potatoes and cut medium dice into square pieces. To prevent any browning, place the already cut potatoes in a bowl filled with water.\r\nIn the meantime, heat 1-2 tablespoons of oil in a large skillet over medium-high heat. Tilt the skillet so the oil spreads evenly.\r\nOnce the oil is hot, drain the potatoes and add to the skillet. Season with salt, pepper, and Old Bay as needed.\r\nCook for 10 minutes, stirring the potatoes often, until brown. If needed, add a tablespoon more of oil.\r\nChop up the bacon and add to the potatoes. The bacon will start to render and the fat will begin to further cook the potatoes. Toss it up a bit! The bacon will take 5-6 minutes to crisp.\r\nOnce the bacon is cooked, reduce the heat to medium-low, add the minced garlic and toss. Season once more. Add dried or fresh parsley. Control heat as needed.\r\nLet the garlic cook until fragrant, about one minute.\r\nJust before serving, drizzle over the maple syrup and toss. Let that cook another minute, giving the potatoes a caramelized effect.\r\nServe in a warm bowl with a sunny side up egg!', 'https://www.themealdb.com/images/media/meals/1550441882.jpg', 'Potatoes, Olive Oil, Bacon, Garlic Clove, Maple Syrup, Parsley, Salt, Pepper, Allspice', '3 Medium, 1 tbs, 2 strips, Minced, 1 tbs, Garnish, Pinch, Pinch, To taste', 'https://www.youtube.com/watch?v=BoD0TIO9nE4'),
(52895, 'English Breakfast', 'Breakfast', 'British', 'Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.\r\nCook the sausages first. Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden. After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients. If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven.\r\nSnip a few small cuts into the fatty edge of the bacon. Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached. Like the sausages, the cooked bacon can be kept hot on a plate in the oven.\r\nFor the mushrooms, brush away any dirt using a pastry brush and trim the stalk level with the mushroom top. Season with salt and pepper and drizzle over a little olive oil. Place stalk-side up on the grill plate and cook for 1-2 minutes before turning and cooking for a further 3-4 minutes. Avoid moving the mushrooms too much while cooking, as this releases the natural juices, making them soggy.\r\nFor the tomatoes, cut the tomatoes across the centre/or in half lengthways if using plum tomatoes , and with a small, sharp knife remove the green \'eye\'. Season with salt and pepper and drizzle with a little olive oil. Place cut-side down on the grill plate and cook without moving for 2 minutes. Gently turn over and season again. Cook for a further 2-3 minutes until tender but still holding their shape.\r\nFor the black pudding, cut the black pudding into 3-4 slices and remove the skin. Place on the grill plate and cook for 1½-2 minutes each side until slightly crispy.\r\nFor \'proper\' fried bread it\'s best to cook it in a separate pan. Ideally, use bread that is a couple of days old. Heat a frying pan to a medium heat and cover the base with oil. Add the bread and cook for 2-3 minutes each side until crispy and golden. If the pan becomes too dry, add a little more oil. For a richer flavour, add a knob of butter after you turn the slice.\r\nFor the fried eggs, break the egg straight into the pan with the fried bread and leave for 30 seconds. Add a good knob of butter and lightly splash/baste the egg with the butter when melted. Cook to your preferred stage, season and gently remove with a fish slice.\r\nOnce all the ingredients are cooked, serve on warm plates and enjoy straight away with a good squeeze of tomato ketchup or brown sauce.', 'https://www.themealdb.com/images/media/meals/utxryw1511721587.jpg', 'Sausages, Bacon, Mushrooms, Tomatoes, Black Pudding, Eggs, Bread', '2, 3, 2, 2, 1 Slice, 2, 1 Slice', 'https://www.youtube.com/watch?v=FXjYU2Ensck'),
(52896, 'Full English Breakfast', 'Breakfast', 'British', 'Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.\r\nCook the sausages first. Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden. After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients. If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven.\r\nSnip a few small cuts into the fatty edge of the bacon. Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached. Like the sausages, the cooked bacon can be kept hot on a plate in the oven.\r\nFor the mushrooms, brush away any dirt using a pastry brush and trim the stalk level with the mushroom top. Season with salt and pepper and drizzle over a little olive oil. Place stalk-side up on the grill plate and cook for 1-2 minutes before turning and cooking for a further 3-4 minutes. Avoid moving the mushrooms too much while cooking, as this releases the natural juices, making them soggy.\r\nFor the tomatoes, cut the tomatoes across the centre/or in half lengthways if using plum tomatoes , and with a small, sharp knife remove the green \'eye\'. Season with salt and pepper and drizzle with a little olive oil. Place cut-side down on the grill plate and cook without moving for 2 minutes. Gently turn over and season again. Cook for a further 2-3 minutes until tender but still holding their shape.\r\nFor the black pudding, cut the black pudding into 3-4 slices and remove the skin. Place on the grill plate and cook for 1½-2 minutes each side until slightly crispy.\r\nFor \'proper\' fried bread it\'s best to cook it in a separate pan. Ideally, use bread that is a couple of days old. Heat a frying pan to a medium heat and cover the base with oil. Add the bread and cook for 2-3 minutes each side until crispy and golden. If the pan becomes too dry, add a little more oil. For a richer flavour, add a knob of butter after you turn the slice.\r\nFor the fried eggs, break the egg straight into the pan with the fried bread and leave for 30 seconds. Add a good knob of butter and lightly splash/baste the egg with the butter when melted. Cook to your preferred stage, season and gently remove with a fish slice.\r\nOnce all the ingredients are cooked, serve on warm plates and enjoy straight away with a good squeeze of tomato ketchup or brown sauce.', 'https://www.themealdb.com/images/media/meals/sqrtwu1511721265.jpg', 'Sausages, Bacon, Mushrooms, Tomatoes, Black Pudding, Eggs, Bread, Baked Beans', '4, 4, 4, 3, 2 sliced, 2, 1 Slice, 100g', 'https://www.youtube.com/watch?v=FXjYU2Ensck'),
(53363, 'Jamaican Cornmeal Porridge', 'Breakfast', 'Jamaican', 'Add 2 ½ cups water, 1 can coconut milk to a 4 QT heavy bottomed pot. Bring to a boil over medium-high heat.\r\nMeanwhile, add 1 cup cornmeal and 1 ½ cup water to a large mixing cup and whisk until smooth.\r\nOnce the pot begins to boil, whisk in cornmeal mixture and continue to whisk for about 1 minute, ensuring there are no lumps. Reduce heat to low and cover with a tight fitting lid.\r\nCook over low heat for 15-20 minutes, stirring occasionally. When there is about 5 minutes left, stir in vanilla extract, cinnamon, nutmeg, and all-spice. Remove from heat and sweeten with condensed milk.\r\nServe and enjoy.', 'https://www.themealdb.com/images/media/meals/sng9bm1765320170.jpg', 'Water, Coconut Milk, Fine Yellow Cornmeal, Vanilla Extract, Ground Cinnamon, Ground Nutmeg, Ground Allspice, Sweetened Condensed Milk', '4 cups, 380g, 1 cup, 1.5 tsp, 0.5 tsp, 0.5 tsp, 0.25 tsp, 0.5 cup', 'https://www.youtube.com/watch?v=NACm9tDACRc'),
(52969, 'Chakchouka', 'Miscellaneous', 'Tunisian', 'In a large cast iron skillet or sauté pan with a lid, heat oil over medium high heat. Add the onion and sauté for 2-3 minutes, until softened. Add the peppers and garlic, and sauté for an additional 3-5 minutes. Add the tomatoes, cumin, paprika, salt, and chili powder. Mix well and bring the mixture to a simmer. Reduce the heat to medium low and continue to simmer, uncovered, 10-15 minutes until the mixture has thickened to your desired consistency. (Taste the sauce at this point and adjust for salt and spice, as desired.) Using the back of a spoon, make four craters in the mixture, large enough to hold an egg. Crack one egg into each of the craters. Cover the skillet and simmer for 5-7 minutes, until the eggs have set. Serve immediately with crusty bread or pita.', 'https://www.themealdb.com/images/media/meals/gpz67p1560458984.jpg', 'Tomatoes, Olive Oil, Onion, Red Pepper, Green Pepper, Garlic, Cumin, Paprika, Salt, Chili Powder, Eggs', '4, 2 tbs, 1 diced, 1 sliced, 1 sliced, 3 cloves crushed, 1 tsp, 1 tsp, 3/4 tsp, 1/2 tsp, 4', 'https://www.youtube.com/watch?v=EHKNu93MSx4'),
(52907, 'Duck Confit', 'Miscellaneous', 'French', 'The day before you want to make the dish, scatter half the salt, half the garlic and half of the herbs over the base of a small shallow dish. Lay the duck legs, skin-side up, on top, then scatter over the remaining salt, garlic and herbs. Cover the duck and refrigerate overnight. This can be done up to 2 days ahead.\r\nPour the wine into a saucepan that will snugly fit the duck legs in a single layer. Brush the salt off the duck legs and place them, skin-side down, in the wine. Cover the pan with a lid and place over a medium heat. As soon as the wine starts to bubble, turn the heat down to the lowest setting and cook for 2 hours, checking occasionally that the liquid is just barely simmering.\r\nAfter 2 hours, the duck legs should be submerged in their own fat and the meat should feel incredibly tender when prodded. Leave to cool.\r\nThe duck legs are now cooked and can be eaten immediately or crisped later. To reheat, roast at 220C for 30-40 mins until crisp.', 'https://www.themealdb.com/images/media/meals/wvpvsu1511786158.jpg', 'Sea Salt, Bay Leaf, Garlic, Thyme, Duck Legs, White Wine', 'Handful, 4, 4 cloves, Handful, 4, 100ml', 'https://www.youtube.com/watch?v=MHhLJqghY-o'),
(52915, 'French Omelette', 'Miscellaneous', 'French', 'Get everything ready. Warm a non-stick frying pan on medium heat. Beat eggs lightly. Add butter to pan. Pour eggs with seasoning. Stir gently and fold. Cook until soft and slightly set. Fold and serve immediately.', 'https://www.themealdb.com/images/media/meals/yvpuuy1511797244.jpg', 'Eggs, Butter, Parmesan, Tarragon Leaves, Parsley, Chives, Gruyère', '3, 2 knobs, 1 tsp, 3 chopped, 1 tbsp chopped, 1 tbsp chopped, 4 tbsp', 'https://www.youtube.com/watch?v=qXPhVYpQLPA'),
(52810, 'Osso Buco alla Milanese', 'Miscellaneous', 'Italian', 'Heat oven to 300 degrees. Coat veal shanks with flour. Brown in oil and butter. Remove and cook vegetables. Add wine, stock, tomatoes and reduce. Return meat and braise in oven for about 2 hours until tender. Prepare gremolata and finish before serving.', 'https://www.themealdb.com/images/media/meals/wwuqvt1487345467.jpg', 'Veal, Flour, Olive Oil, Butter, Onion, Carrots, Celery, Fennel, Garlic, Orange Zest, Marjoram, Bay Leaf, White Wine, Chicken Stock, Tomatoes, Parsley, Garlic, Lemon Zest', '4 shanks, 1/2 cup, 2 tbsp, 3 tbsp, 1 chopped, 1 chopped, 1 chopped, 1 bulb, 3 cloves, 2 strips, 1.5 tsp, 1, 1 cup, 1/2 cup, 1 cup, 2 tbsp, 1 tsp, 1 tsp', 'https://www.youtube.com/watch?v=9GUTC2Qwrf0'),
(53014, 'Pizza Margherita', 'Miscellaneous', 'Italian', 'Preheat oven to 230C. Mix yeast, sugar and warm water and let activate. Add flour, salt and oil and knead dough. Let rise. Spread passata, add cheese and toppings. Bake 10-12 minutes until done. Garnish with basil.', 'https://www.themealdb.com/images/media/meals/x0lk931587671540.jpg', 'Water, Sugar, Yeast, Flour, Salt, Olive Oil, Passata, Mozzarella, Oregano, Basil, Black Pepper', '150ml, 1 tsp, 15g, 225g, 1.5 tsp, drizzle, 80g, 70g, to taste, leaves, pinch', 'https://www.youtube.com/watch?v=Mt5lgUZRoUg'),
(53383, 'Ramen Noodles with Boiled Egg', 'Miscellaneous', 'Chinese', 'Boil: Bring water to a boil, gently add eggs, and cook for exactly 6½ to 7 minutes.\r\nIce Bath: Immediately transfer the eggs to a bowl of ice water for 3–5 minutes to stop cooking.\r\nMarinate (Optional but recommended): Peel the eggs and marinate in a mix of 2 tbsp soy sauce, 2 tbsp mirin, 1 tsp sugar, and 4 tbsp water for at least 4 hours (or overnight).\r\nServe: Slice in half, letting the yolk flow into the broth.', 'https://www.themealdb.com/images/media/meals/ip5xtp1769779958.jpg', 'Noodles, Water, Egg, Soy Sauce, Chilli Sauce, Spring Onions, Salt, Pepper', '1 packet, 2 cups, 1 large, 1 tbsp, 1/2 tsp, 1 tbsp, 1/2 tsp, 1/2 tbsp', 'https://www.youtube.com/watch?v=AbJNVnkndS4'),
(53215, 'Shakshouka', 'Miscellaneous', 'Saudi Arabian', 'First, pan fry the black pepper and garlic over a dry medium heat until fragrant.\r\nAdd a good amount of extra virgin olive oil and infuse for a minute.\r\nOnce the oil heats up, add the tomatoes and salt, and cover with a lid. Simmer for 5 minutes.\r\nRemove the lid and mash the tomatoes. Reduce until you reach the desired consistency.\r\nMake craters for the eggs and lower the heat. Crack eggs into the craters.\r\nCover and cook for 5 minutes. Let rest for 1-2 minutes before serving with flatbread.', 'https://www.themealdb.com/images/media/meals/crd1jz1763592990.jpg', 'Tomato, Olive Oil, Egg, Garlic, Black Pepper, Salt', '250g, 40 ml, 4, 4 sliced, to taste, to taste', 'https://www.youtube.com/watch?v=618QsMaVXp8'),
(53219, 'Shakshuka Feta Cheese', 'Miscellaneous', 'Saudi Arabian', 'In a pan heat oil. Add vegetables (onion, garlic, celery, red pepper) and cook 5 mins.\r\nAdd cumin, salt, pepper and tomato sauce, cook 7 mins.\r\nAdd eggs and cook covered for 8 mins.\r\nAdd spinach and feta at the end. Serve with bread.', 'https://www.themealdb.com/images/media/meals/wpkfin1763597958.jpg', 'Egg, Tomato Sauce, Olive Oil, Shallots, Celery, Garlic, Spinach, Feta, Red Pepper, Cumin, Salt, Black Pepper', '4 large, 3 tbsp, 1 tbsp, 1 chopped, 1, 1 clove, 1 cup, 1/2 cup, 1/2, 1 tsp, 1/2 tsp, 1/2 tsp', 'https://www.youtube.com/watch?v=xaBo3BxKzp8'),
(52912, 'Three-cheese souffles', 'Miscellaneous', 'French', 'Heat oven to 200C. Butter ramekins and coat with Parmesan.\r\nHeat milk with bay leaves, infuse 15 mins.\r\nAdd butter and flour, cook into thick sauce.\r\nMix mustard, pepper, cheese and egg yolks.\r\nBeat egg whites and fold in gently.\r\nFill ramekins and bake 20-25 mins until risen and golden.', 'https://www.themealdb.com/images/media/meals/sxwquu1511793428.jpg', 'Butter, Parmesan, Milk, Bay Leaves, Flour, Mustard, Cayenne Pepper, Gruyère, Eggs, Goats Cheese, Cream, Spinach', '50g, 25g, 300ml, 2, 5 tbsp, 1/2 tsp, pinch, 140g, 3, 8 slices, 150ml, to serve', 'https://www.youtube.com/watch?v=mS_gbQpBvZo'),
(53249, 'Turkey Banh Mi', 'Miscellaneous', 'Vietnamese', 'Make pickled slaw with carrots, cabbage, vinegar, sugar and salt. Rest 15 mins.\r\nFill baguette with pate, slaw, cucumber, turkey.\r\nAdd mayo with chilli, garnish with mint and serve.', 'https://www.themealdb.com/images/media/meals/1wj8w31763781990.jpg', 'Baguette, Chicken Liver, Cucumber, Turkey, Mayonnaise, Red Chilli, Mint, Carrots, Cabbage, Ginger, Vinegar, Sugar', '2 small, 50g, 1/4, 140g, 1 tbsp, 1 sliced, handful, 2 small, 75g, 1/4 tsp, 1/2 tbsp, 1/2 tsp', 'https://www.youtube.com/watch?v=L-ItzFfVgos'),
(53252, 'Turkish Rice', 'Miscellaneous', 'Turkish', 'Wash rice until water runs clear and soak 10 mins.\r\nCook vermicelli in oil until golden, add butter.\r\nAdd drained rice and stir.\r\nAdd stock and salt, bring to boil then simmer 7-9 mins.\r\nRest covered 10 mins, fluff and serve.', 'https://www.themealdb.com/images/media/meals/xw1ruy1763786501.jpg', 'Rice, Vegetable Oil, Vermicelli, Butter, Chicken Stock', '300g, 3 tbsp, 70g, 30g, 600ml', 'https://www.youtube.com/watch?v=gY6PZzjO53M'),
(52839, 'Chilli prawn linguine', 'Pasta', 'Italian', 'Mix the dressing ingredients in a small bowl and season with salt and pepper. Set aside. Cook the pasta according to the packet instructions. Add the sugar snap peas for the last minute or so of cooking time. Meanwhile, heat the oil in a wok or large frying pan, toss in the garlic and chilli and cook over a fairly gentle heat for about 30 seconds without letting the garlic brown. Tip in the prawns and cook over a high heat, stirring frequently, for about 3 minutes until they turn pink. Add the tomatoes and cook, stirring occasionally, for 3 minutes until they just start to soften. Drain the pasta and sugar snaps well, then toss into the prawn mixture. Tear in the basil leaves, stir, and season with salt and pepper. Serve with salad leaves drizzled with the lime dressing, and warm crusty bread.', 'https://www.themealdb.com/images/media/meals/usywpp1511189717.jpg', 'Linguine Pasta, Sugar Snap Peas, Olive Oil, Garlic Clove, Red Chilli, King Prawns, Cherry Tomatoes, Basil Leaves, Lettuce, Bread, Fromage Frais, Lime, Caster Sugar', '280g, 200g, 2 tblsp, 2 cloves chopped, 1 large, 24 Skinned, 12, Handful, Leaves, to serve, 2 tbsp, Grated Zest of 2, 2 tsp', 'https://www.youtube.com/watch?v=SC17Mc70Db0'),
(53064, 'Fettuccine Alfredo', 'Pasta', 'Italian', 'Cook pasta according to package instructions in a large pot of boiling water and salt. Add heavy cream and butter to a large skillet over medium heat until the cream bubbles and the butter melts. Whisk in parmesan and add seasoning (salt and black pepper). Let the sauce thicken slightly and then add the pasta and toss until coated in sauce. Garnish with parsley, and it\'s ready.', 'https://www.themealdb.com/images/media/meals/0jv5gx1661040802.jpg', 'Fettuccine, Heavy Cream, Butter, Parmesan, Parsley, Black Pepper', '1 lb, 1/2 cup, 1/2 cup, 1/2 cup, 2 tbsp, ', 'https://www.youtube.com/watch?v=LPPcNPdq_j4'),
(52835, 'Fettucine alfredo', 'Pasta', 'Italian', 'In a medium saucepan, stir the clotted cream, butter and cornflour over a low-ish heat and bring to a low simmer. Turn off the heat and keep warm. Meanwhile, put the cheese and nutmeg in a small bowl and add a good grinding of black pepper, then stir everything together. Put the pasta in another pan with 2 tsp salt, pour over some boiling water and cook following pack instructions (usually 3-4 mins). When cooked, scoop some of the cooking water into a heatproof jug or mug and drain the pasta, but not too thoroughly. Add the pasta to the pan with the clotted cream mixture, then sprinkle over the cheese and gently fold everything together over a low heat using a rubber spatula. When combined, splash in 3 tbsp of the cooking water. Keep stirring until the water is absorbed and the sauce is glossy. Sprinkle over some chives or parsley, then serve immediately.', 'https://www.themealdb.com/images/media/meals/uquqtu1511178042.jpg', 'Clotted Cream, Butter, Corn Flour, Parmesan Cheese, Nutmeg, Fettuccine, Parsley', '227g, 25g, 1 tsp, 100g, Grated, 250g, Chopped', 'https://www.youtube.com/watch?v=FLEnwZvGzOE');
INSERT INTO `recipes` (`id`, `name`, `category`, `area`, `instructions`, `thumbnail`, `all_ingredients`, `all_measures`, `youtube`) VALUES
(52987, 'Lasagna Sandwiches', 'Pasta', 'American', '1. In a small bowl, combine the first four ingredients; spread on four slices of bread. Layer with bacon, tomato and cheese; top with remaining bread. 2. In a large skillet or griddle, melt 2 tablespoons butter. Toast sandwiches until lightly browned on both sides and cheese is melted, adding butter if necessary.', 'https://www.themealdb.com/images/media/meals/xr0n4r1576788363.jpg', 'Sour Cream, Chopped Onion, Dried Oregano, Salt, Bread, Bacon, Tomato, Mozzarella, Butter', '1/4 cup, 2 tbs, 1/2 tbs, 1/4 tsp, 8 slices, 8 slices, 8 slices, 4 slices, 2 1/2 Tbs', ''),
(52837, 'Pilchard puttanesca', 'Pasta', 'Italian', 'Cook the pasta following pack instructions. Heat the oil in a non-stick frying pan and cook the onion, garlic and chilli for 3-4 mins to soften. Stir in the tomato purée and cook for 1 min, then add the pilchards with their sauce. Cook, breaking up the fish with a wooden spoon, then add the olives and continue to cook for a few more mins. Drain the pasta and add to the pan with 2-3 tbsp of the cooking water. Toss everything together well, then divide between plates and serve, scattered with Parmesan.', 'https://www.themealdb.com/images/media/meals/vvtvtr1511180578.jpg', 'Spaghetti, Olive Oil, Onion, Garlic, Red Chilli, Tomato Puree, Pilchards, Black Olives, Parmesan', '300g, 1 tbls, 1 finely chopped, 2 cloves minced, 1, 1 tbls, 425g, 70g, Shaved', 'https://www.youtube.com/watch?v=wqZzLAPmr9k'),
(52982, 'Spaghetti alla Carbonara', 'Pasta', 'Italian', 'Put a large saucepan of water on to boil. Finely chop the 100g pancetta. Finely grate 50g pecorino cheese and 50g parmesan and mix them together. Beat the 3 large eggs in a medium bowl and season with black pepper. Add 1 tsp salt to the boiling water, cook 350g spaghetti until al dente. While the spaghetti is cooking, fry the pancetta with bruised garlic in 50g butter until golden and crisp. Discard garlic. Lift pasta into the pan with pancetta. Take off heat, pour in eggs and cheese. Lift the spaghetti so it mixes with the egg mixture, which thickens but doesn’t scramble. Add extra pasta cooking water to keep it saucy. Season and serve immediately.', 'https://www.themealdb.com/images/media/meals/llcbn01574260722.jpg', 'Spaghetti, Egg Yolks, Salt, Bacon, Pecorino, Black Pepper', '320g, 6, As required, 150g, 50g, As required', 'https://www.youtube.com/watch?v=_T6jkRvhlkk'),
(52838, 'Venetian Duck Ragu', 'Pasta', 'Italian', 'Heat the oil, brown duck legs for 10 mins. Remove and set aside. Cook onions until softened, add garlic, cinnamon and flour. Return duck, add wine, tomatoes, stock, herbs, sugar and seasoning. Simmer covered for 2 hrs. Lift duck out, shred meat and discard fat and bones. Add meat back to sauce with milk and simmer for 10-15 mins. Cook pasta, drain and add to the ragu. Stir to coat and cook for 1 min more. Serve with Parmesan.', 'https://www.themealdb.com/images/media/meals/qvrwpt1511181864.jpg', 'Olive Oil, Duck Legs, Onions, Garlic, Cinnamon, Plain Flour, Red Wine, Chopped Tomatoes, Chicken Stock Cube, Rosemary, Bay Leaves, Sugar, Milk, Paccheri Pasta, Parmesan Cheese', '1 tbls, 4, 2 finely chopped, 2 cloves minced, 2 tsp ground, 2 tsp, 250ml, 800g, 1, 3 sprigs, 2, 1 tsp, 2 tbs, 600g, Grated', 'https://www.youtube.com/watch?v=oWQDVgjB_Lw'),
(53242, 'Barbecue pork buns', 'Pork', 'Vietnamese', 'step 1: Heat the oven to 200C/fan 180C/gas. Mix the sugar into the bread mix in a large bowl, then add water as instructed on the pack. Bring the dough together with a wooden spoon, then knead on a lightly floured surface for 5 mins until smooth. Put into a large bowl, cover with oiled cling film then leave in a warm place until doubled in size. step 2: Meanwhile, heat the oil in a pan, then fry the bacon until crisp, about 5 mins. Add the ginger and garlic and fry for 1 min until soft, then tip in the soy, honey and tomato purée and stir well. step 3: Turn out the dough and knead briefly, then pull into 12 even-sized balls. Flatten with your hands, then put a teaspoon-size blob of the filling in the middle. Draw the dough up and pinch it closed like a purse, then turn the bun over and sit it on a large baking sheet. Cover with oiled cling film and leave to rise for about 30 mins until the dough feels pillowy. Brush with egg and bake for 20 mins until golden. Serve warm with dipping sauce.', 'https://www.themealdb.com/images/media/meals/tzsy461763769901.jpg', 'Sugar, White Bread Mix, Sunflower Oil, Bacon, Ginger, Garlic, Soy Sauce, Clear Honey, Tomato Puree, Egg', '85g, 500g, 1 tablespoon, 12, Knob, 2 cloves chopped, 2 tablespoons, 3 tablespoons, 3 tablespoons, 1 beaten', 'https://www.youtube.com/watch?v=T3mBULRIcY8'),
(52995, 'BBQ Pork Sloppy Joes', 'Pork', 'American', '1. Preheat oven to 450 degrees. Wash and dry all produce. Cut sweet potatoes into ½-inch-thick wedges. Toss on a baking sheet with a drizzle of oil, salt, and pepper. Roast until browned and tender, 20-25 minutes. 2. Meanwhile, halve and peel onion. Slice as thinly as possible until you have ¼ cup; finely chop remaining onion. Peel and finely chop garlic. Halve lime; squeeze juice into a small bowl. Halve buns. Add 1 TBSP butter to a separate small microwave-safe bowl; microwave until melted, 30 seconds. Brush onto cut sides of buns. 3. To bowl with lime juice, add sliced onion, ¼ tsp sugar, and a pinch of salt. Stir to combine; set aside to quick-pickle. 4. Heat a drizzle of oil in a large pan over medium-high heat. Add chopped onion and season with salt and pepper. Cook, stirring, until softened, 4-5 minutes. Add garlic and cook until fragrant, 30 seconds more. Add pork and season with salt and pepper. Cook, breaking up meat into pieces, until browned and cooked through, 4-6 minutes. 5. While pork cooks, in a third small bowl, combine BBQ sauce, pickling liquid from onion, 3 TBSP ketchup, ½ tsp sugar, and ¼ cup water. Once pork is cooked through, add BBQ sauce mixture to pan. Cook, stirring, until sauce is thickened, 2-3 minutes. 6. Meanwhile, toast buns in oven or toaster oven until golden, 3-5 minutes. Divide toasted buns between plates and fill with as much BBQ pork as you’d like. Top with pickled onion and hot sauce. Serve with sweet potato wedges on the side.', 'https://www.themealdb.com/images/media/meals/atd5sh1583188467.jpg', 'Potatoes, Red Onions, Garlic, Lime, Bread, Pork, Barbeque Sauce, Hotsauce, Tomato Ketchup, Sugar, Vegetable Oil, Salt, Pepper', '2, 1, 2 cloves, 1, 2, 1 lb, , , , , , , ', ''),
(53018, 'Bigos (Hunters Stew)', 'Pork', 'Polish', 'Preheat the oven to 350 degrees F (175 degrees C). Heat a large pot over medium heat. Add the bacon and kielbasa; cook and stir until the bacon has rendered its fat and sausage is lightly browned. Use a slotted spoon to remove the meat and transfer to a large casserole or Dutch oven. Coat the cubes of pork lightly with flour and fry them in the bacon drippings over medium-high heat until golden brown. Use a slotted spoon to transfer the pork to the casserole. Add the garlic, onion, carrots, fresh mushrooms, cabbage and sauerkraut. Reduce heat to medium; cook and stir until the carrots are soft, about 10 minutes. Deglaze the pan by pouring in the red wine and stirring to loosen all bits. Season with bay leaf, basil, marjoram, paprika, salt, pepper, caraway seeds and cayenne pepper; cook for 1 minute. Mix in dried mushrooms, hot pepper sauce, Worcestershire sauce, beef stock, tomato paste and tomatoes. Heat through just until boiling. Pour the vegetables and all of the liquid into the casserole dish with the meat. Cover with a lid. Bake for 2 1/2 to 3 hours, until meat is very tender.', 'https://www.themealdb.com/images/media/meals/md8w601593348504.jpg', 'Bacon, Kielbasa, Pork, Flour, Garlic, Onion, Mushrooms, Cabbage, Sauerkraut, Red Wine, Bay Leaf, Basil, Marjoram, Paprika, Caraway Seed, Hotsauce, Beef Stock, Tomato Puree, Diced Tomatoes, Worcestershire Sauce', '2 sliced, 1 lb, 1 lb, 1/4 cup, 3 chopped, 1 Diced, 1 1/2 cup, 4 cups, 1 Jar, 1/4 cup, 1, 1 tsp, 1 tsp, 1 tbs, 1/8 teaspoon, 1 dash, 5 Cups, 2 tbs, 1 cup, 1 dash', 'https://www.youtube.com/watch?v=Oqg_cO4s8ik'),
(53190, 'Bryndzové Halušky', 'Pork', 'Slovakian', '1. Prepare the Dough: Grate the potatoes finely. Mix with flour, egg, and salt until a sticky dough forms. 2. Cook the Dumplings: Press dough into boiling salted water. Cook until they float (2-3 mins). 3. Prepare the Toppings: Fry bacon until crispy. Mix feta with sour cream if using as a substitute. 4. Assemble: Toss dumplings with cheese until creamy. Top with crispy bacon and chives.', 'https://www.themealdb.com/images/media/meals/g33c901763365484.jpg', 'Potatoes, Plain Flour, Egg, Salt, Bryndza cheese, Bacon, Chives', '500g, 200g, 1, 1 teaspoon, 250g, 200g, Garnish', 'https://www.youtube.com/shorts/IPF_VpH7FzI'),
(53330, 'Cassava pizza', 'Pork', 'Venezulan', 'Preheat oven to 200ºC. Cut bacon/chorizo into medium pieces and paprika into strips. Spread tomato sauce and mozzarella on each cassava portion. Add bacon/chorizo, corn, turkey ham, olives, and paprika. Bake for 7 to 10 minutes.', 'https://www.themealdb.com/images/media/meals/lrfdwz1764438393.jpg', 'Casabe, Tomato Sauce, Chorizo, Turkey Ham, Sweetcorn, Green Olives, Paprika, Mozzarella', '6 cut thick slices, 450g, 225g, 225g, 75g, 40g, 55g, 50g', 'https://www.youtube.com/watch?v=3fK4zsa2AYM'),
(53136, 'Choripán', 'Pork', 'Argentinian', 'Grill the Chorizos for 10-15 minutes. Slice and toast the rolls. Slice each chorizo lengthwise, place in a roll, and top with chimichurri sauce. Serve hot.', 'https://www.themealdb.com/images/media/meals/5i25sg1763075353.jpg', 'Chorizo, Crusty Bread, Chimichurri sauce', '4, 4, Drizzle', 'https://www.youtube.com/watch?v=FNrU5mQKFOE'),
(53179, 'Ham croquetas', 'Pork', 'Spanish', '1. Sauté leek and ham, stir in flour and fry until golden. 2. Gradually add warm milk/stock mixture with nutmeg, stirring until thick. 3. Chill the mixture for 1 hr. 4. Shape into balls, coat in flour, then egg, then breadcrumbs. 5. Chill for 30 mins and deep-fry at 180C until golden.', 'https://www.themealdb.com/images/media/meals/6dpa7m1763331105.jpg', 'Plain Flour, Egg, Breadcrumbs, Sunflower Oil, Extra Virgin Olive Oil, Leek, jamón ibérico, Plain Flour, Vegetable Stock, Milk, Nutmeg', '75g, 2 large, 75g, For frying, 4 tbsp, 1/2, 70g, 60g, 75 ml, 330ml, Grated', 'https://www.youtube.com/shorts/nT8MGiWldHk'),
(53035, 'Ham hock colcannon', 'Pork', 'Irish', '1. Boil potatoes until soft. 2. Sauté garlic, cabbage, and spring onions in butter until wilted. 3. Mash potatoes with cream and mustard, then stir in cabbage and ham. 4. Serve topped with a fried egg.', 'https://www.themealdb.com/images/media/meals/n41ny81608588066.jpg', 'Floury Potatoes, Butter, Garlic Clove, Cabbage, Spring Onions, Double Cream, Mustard, Ham, Eggs', '800g, 50g, 3 chopped, 1 chopped, 8, 100ml, 2 tbs, 180g, 4', 'https://www.youtube.com/watch?v=aQJAU2iJ730'),
(53227, 'Rice paper dumplings', 'Pork', 'Vietnamese', '1. Blitz cabbage, salt, and squeeze out water. Mix with pork, carrot, mushrooms, garlic, ginger, soy sauce, and sesame oil. 2. Soak rice paper in warm water. Wrap 1 tbsp of filling in each sheet to make a square. 3. Fry in oil for 3-5 mins until golden, then cover and cook for another 3-4 mins. 4. Serve with dipping sauce.', 'https://www.themealdb.com/images/media/meals/sfahy01763752319.jpg', 'White Cabbage, Carrots, Shiitake Mushrooms, Ground Pork, Garlic, Ginger, Soy Sauce, Sesame Seed Oil, Spring Onions, Rice Paper Sheets, Vegetable Oil, Rice Vinegar, Sesame Seed', '1/4, 1, 100g, 400g, 2 cloves minced, 20g, 2 tsp, 2 tsp, 3 sliced thinly, 20, 75 ml, 2 tablespoons, 1/2 tbs', 'https://www.youtube.com/shorts/YU09jIusxo4'),
(52948, 'Wontons', 'Pork', 'Chinese', 'Combine pork, garlic, ginger, soy sauce, and veggies. Place filling in wonton skin, fold into a triangle, and pinch edges. Fry in 450-degree oil until golden. Drain and serve.', 'https://www.themealdb.com/images/media/meals/1525876468.jpg', 'Pork, Garlic Clove, Ginger, Soy Sauce, Sesame Seed Oil, Carrots, Celery, Spring Onions, Wonton Skin, Oil, Water', '1lb, 3 chopped, 1 tsp, 1 tbs, 1 tsp, 3 finely chopped, 3 finely chopped, 6 chopped, 1 Packet, Fry, Bottle', 'https://www.youtube.com/watch?v=9h9No18ZyCI'),
(53235, 'Vietnamese-style caramel pork', 'Pork', 'Vietnamese', '1. Stir-fry pork batches in oil until browned. 2. Sauté shallots, ginger, and chilli. Add sugar, fish sauce, and water. 3. Return pork to pan and bubble for 8-10 mins until sauce thickens and glazes the meat. 4. Top with spring onions and serve with rice.', 'https://www.themealdb.com/images/media/meals/4mzt101763761546.jpg', 'Ground Nut Oil, Pork Shoulder Steaks, Shallots, Ground Ginger, Red Chilli, Brown Sugar, Fish Sauce, Chilli Sauce, Spring Onions, Rice, Pak Choi', '1 ½ tbsp, 500g, 2 chopped, 1 tablespoon, 1 chopped, 75g, 1 tablespoon, 2 tsp, 4, Steamed, To serve', 'https://www.youtube.com/watch?v=qmQe0Qxvyzc'),
(53237, 'Vietnamese pork salad', 'Pork', 'Vietnamese', '1. Dressing: Dissolve sugar in lime juice/water. Blend with chilli/coriander; stir in sesame oil and fish sauce. 2. Pork: Griddle pork to sear, then bake at 200C for 10-12 mins. Slice thinly and toss in half the dressing. 3. Serve: Toss salad veggies with remaining dressing and top with pork slices.', 'https://www.themealdb.com/images/media/meals/g7jomp1763763994.jpg', 'Golden Caster Sugar, Lime, Red Chilli, Coriander, Sesame Seed Oil, Fish Sauce, Soy Sauce, Pork Tenderloin, Vegetable Oil, White Cabbage, Cucumber, Celery, Spring Onions, Lemongrass Stalks, Mint', '1 tsp, Juice of 2, 1 chopped, Handful, 1 tablespoon, 1 tablespoon, 1 tablespoon, 500g, For brushing, 1/4, 1 chopped, 5 chopped, 3 sliced thinly, 2 chopped, Handful', 'https://www.youtube.com/watch?v=_DCJNrNTTB4'),
(52926, 'Tourtiere', 'Pork', 'Canadian', '1. Boil and mash potato. 2. Fry minced pork and onion until browned; add garlic, spices, and stock. 3. Mix with potato and cool. 4. Line a pie tin with pastry, fill with meat, and cover with more pastry. 5. Glaze with egg and bake at 200C for 30 mins until golden.', 'https://www.themealdb.com/images/media/meals/ytpstt1511814614.jpg', 'Potatoes, Sunflower Oil, Minced Pork, Onion, Garlic Clove, Cinnamon, Allspice, Nutmeg, Vegetable Stock, Shortcrust Pastry, Egg', '1 medium, 1 tsp, 500g, 1 finely chopped, 1 finely chopped, ¼ tsp, ¼ tsp, ¼ tsp, 100ml, 400g, To Glaze', 'https://www.youtube.com/watch?v=A96hbwobKKs'),
(53032, 'Tonkatsu pork', 'Pork', 'Japanese', '1. Bash pork loins to 1cm thickness. 2. Coat meat in flour, then eggs, and panko breadcrumbs. 3. Fry in 2cm deep oil at 180C for 1.5 mins per side. 4. Rest for 5 mins. 5. Whisk sauce ingredients together and serve over sliced pork.', 'https://www.themealdb.com/images/media/meals/lwsnkl1604181187.jpg', 'Pork Chops, Flour, Eggs, Breadcrumbs, Vegetable Oil, Tomato Ketchup, Worcestershire Sauce, Oyster Sauce, Caster Sugar', '4, 100g, 2 Beaten, 100g, Fry, 2 tbs, 2 tbs, 1 tbs, 2 tblsp', 'https://www.youtube.com/watch?v=aASr5x0d3Ys'),
(53147, 'Arroz con gambas y calamar', 'Seafood', 'Spanish', '1. Fry onion until softened, then add bay leaf, saffron, rice, and tomato purée. 2. Pour in wine and seafood stock; cook for 5 mins. 3. Add squid and simmer for 12 mins. 4. Stir in prawns, cover, and cook for 5-6 mins until prawns are pink.', 'https://www.themealdb.com/images/media/meals/jc6oub1763196663.jpg', 'Raw King Prawns, Olive Oil, Onion, Bay Leaf, Saffron, Paella Rice, Tomato Puree, White Wine, Seafood stock, Squid', '24, 2 tbsp, 1 small, 1, 1 pinch, 450g, 2 teaspoons, 200ml, 650ml, 3 Medium', 'https://www.youtube.com/watch?v=nFFp0ebOlOo'),
(53239, 'Bang bang prawn salad', 'Seafood', 'Vietnamese', '1. Cook and rinse rice noodles. 2. Melt peanut butter, coconut milk, sweet chilli sauce, and half the spring onions in a pan to make the sauce. 3. Mix noodles, cucumber, and beansprouts. 4. Top with prawns and drizzle with the peanut sauce.', 'https://www.themealdb.com/images/media/meals/4xcfai1763765676.jpg', 'Rice Noodles, Peanut Butter, Coconut Milk, sweet chilli sauce, Spring Onions, Cucumber, Bean Sprouts, Prawns', '140g, 3 tablespoons, 4 tablespoons, 3 tablespoons, 3 sliced thinly, 1 sliced, 300g, 200g', 'https://www.youtube.com/watch?v=Na-6-lzs2wU'),
(53154, 'Clam, chorizo & white bean stew', 'Seafood', 'Spanish', '1. Fry chorizo, onion, garlic, and parsley. 2. Add stock, tomatoes, beans, and sherry vinegar; simmer for 10 mins. 3. Add clams, cover, and steam for 2-4 mins until they open. 4. Season and top with fresh parsley.', 'https://www.themealdb.com/images/media/meals/92wbmf1763252334.jpg', 'Chorizo, Onion, Garlic Clove, Parsley, Vegetable Stock, Tinned Tomatos, Butter Beans, Sherry vinegar, Clams, Crusty Bread', '50g, 1 chopped, 1, Bunch, 200ml, 400g, 400g, 1 teaspoon, 600g, To serve', 'https://www.youtube.com/watch?v=IoRuT7TxDAo'),
(52944, 'Escovitch Fish', 'Seafood', 'Jamaican', '1. Season fish and fry until crispy on both sides. 2. Sauté garlic, ginger, onion, peppers, and scotch bonnet. 3. Add vinegar, sugar, and allspice; simmer to make the sauce. 4. Pour the sauce over the fried fish and serve.', 'https://www.themealdb.com/images/media/meals/1520084413.jpg', 'Red Snapper, Vegetable Oil, Garlic, Ginger, Thyme, Bay Leaf, Red Pepper, Yellow Pepper, Onion, Carrots, Sugar, Allspice, Worcestershire Sauce, Scotch Bonnet, Lime, Malt Vinegar, Pepper', '2 Pounds, 1/2 cup, 1 clove, 1/2 tsp, 2 sprigs, 1, 0.5, 0.5, 1 sliced, 1 chopped, 1 tbs, 1/2 tsp, 1 tsp, 1, 1, 3/4 cup, pinch', 'https://www.youtube.com/watch?v=nF6DOtGE6k8'),
(53178, 'Fried calamari', 'Seafood', 'Spanish', '1. Cut squid into rings. 2. Coat squid and capers in seasoned flour. 3. Mix garlic and mayonnaise for the dip. 4. Deep-fry squid in hot oil for 3 mins until crisp. 5. Serve immediately with lemon wedges.', 'https://www.themealdb.com/images/media/meals/yhi46r1763330279.jpg', 'Squid, Plain Flour, Capers, Garlic, Mayonnaise, Vegetable Oil, Lemon', '300g, 200g, 2 tblsp, 1 clove, 5 tblsp, For frying, To serve', 'https://www.youtube.com/watch?v=VcxMq33G-Do'),
(53144, 'Gambas al ajillo', 'Seafood', 'Spanish', '1. Peel and season prawns with salt. 2. Heat olive oil with garlic and chillies. 3. When garlic turns golden, add prawns and cook for 1-2 mins per side until pink. 4. Top with parsley and black pepper.', 'https://www.themealdb.com/images/media/meals/ze8uwg1763196123.jpg', 'Raw King Prawns, Garlic Clove, Olive Oil, Cayenne Pepper, Parsley', '12, 3, 100 ml, 3, 1 tablespoon chopped', 'https://www.youtube.com/watch?v=2tZlO8vNMtk'),
(53180, 'Garlicky prawns with sherry', 'Seafood', 'Spanish', '1. Sauté garlic slices in olive oil. 2. Add prawns and cook until they start turning pink. 3. Pour in dry sherry and simmer until prawns are fully cooked. 4. Sprinkle with fresh parsley before serving.', 'https://www.themealdb.com/images/media/meals/u2lhqb1763331899.jpg', 'Olive Oil, Garlic, Prawns, Dry sherry, Parsley', '3 tablespoons, 3 cloves, 400g, 2 tbsp, Handful', 'https://www.youtube.com/watch?v=2hf2xltFbxQ'),
(53362, 'Jamaican Curry Shrimp Recipe', 'Seafood', 'Jamaican', '1. Season shrimp with curry powder and all-purpose seasoning. 2. Sauté onion, peppers, and garlic. 3. Add more curry powder, then stir in coconut milk, ketchup, and shrimp. 4. Simmer for 5-6 mins until cooked.', 'https://www.themealdb.com/images/media/meals/n7h5zs1765318909.jpg', 'Jumbo Shrimp, Jamaican Curry Powder, All-purpose Seasoning, Olive Oil, Onion, Red Pepper, Green Pepper, Scotch Bonnet, Garlic, Unsweetened Coconut Milk, Tomato Ketchup, Thyme, Salt, Pepper', '1 lb, 2.5 tbsp, 1 tsp, 2 tablespoons, 1 sliced, 1 sliced, 1 sliced, 1 sliced, 3 cloves, 380g, 1/2 tbs, 4 sprigs, To taste, To taste', 'https://www.youtube.com/watch?v=Lnaj4duQ7hs'),
(53349, 'Jamaican Pepper Shrimp', 'Seafood', 'Jamaican', '1. Marinate shrimp with scotch bonnet, seasoning, annatto, and allspice. 2. Simmer shrimp stock with onion and garlic. 3. Add shrimp and thyme; cover and cook for 5-7 mins. 4. Stir in white vinegar and serve with liquid.', 'https://www.themealdb.com/images/media/meals/bx07m71764792853.jpg', 'Shrimp, Scotch Bonnet, All-purpose Seasoning, Ground Annatto, Allspice, Shrimp Stock, Onion, Garlic, White Vinegar, Thyme, Salt', '1 lb, 2 chopped, 1 tablespoon, 2 tsp, 2 tsp, 3/4 cup, 1/4 cup, 2 cloves, 2 tablespoons, 3 sprigs, To taste', 'https://www.youtube.com/watch?v=ILCmxtCp8jc'),
(52852, 'Tuna Nicoise', 'Seafood', 'French', '1. Roast potatoes with oil for 20 mins at 200C. 2. Boil eggs for 8-10 mins, cool, peel, and halve. 3. Whisk oil, vinegar, capers, and tomatoes in a bowl. 4. Toss with onion, spinach, tuna, and potatoes. 5. Top with eggs and serve.', 'https://www.themealdb.com/images/media/meals/yypwwq1511304979.jpg', 'Potatoes, Olive Oil, Eggs, Red Wine Vinegar, Capers, Sunflower Oil, Red Onions, Spinach, Tuna', '450g, 2 tblsp, 4, 1 tbls, 2 tblsp, 50g, ½, 100g, 400g', 'https://www.youtube.com/watch?v=3_UAxkx0u6U'),
(52975, 'Tuna and Egg Briks', 'Seafood', 'Tunisian', '1. Sauté spring onions and spinach until wilted; drain and cool. 2. Mix spinach with tuna, eggs, and hotsauce. 3. Layer 3 filo rounds with oil, add filling, and fold into half-moons. 4. Bake at 200°C for 12-15 mins until golden.', 'https://www.themealdb.com/images/media/meals/2dsltq1560461468.jpg', 'Olive Oil, Spring Onions, Spinach, Filo Pastry, Tuna, Eggs, Hotsauce, Tomatoes, Cucumber, Lemon Juice, Apricot Jam', '2 tbs, 8, 200g, 4, 1 can, 2, Dash, 4 Chopped, 1/4, 1 tbs, 4 tbs', 'https://www.youtube.com/watch?v=C5n1fN8TGHs'),
(53196, 'Tom yum (hot & sour) soup with prawns', 'Seafood', 'Thai', '1. Boil stock with lemongrass, galangal, coriander roots, and lime leaves for 2 mins. 2. Add prawns, fish sauce, chillies, and lime juice. 3. Return to boil, adjust seasoning, and garnish with coriander.', 'https://www.themealdb.com/images/media/meals/9c5nlx1763424766.jpg', 'Chicken Stock, Lemongrass, Galangal, Coriander, makrut lime leaves, King Prawns, Fish Sauce, Green Chilli, Lime juice', '700ml, 1, 5 Slices, 6, 3, 6, 3 tablespoons, 6 small, 4 tablespoons', 'https://www.youtube.com/watch?v=FJer_Cutb2I'),
(52882, 'Three Fish Pie', 'Seafood', 'British', '1. Mash boiled potatoes with butter and milk. 2. Sauté leeks, add flour/wine mix, then milk to thicken. 3. Stir in parsley and fish, then top with boiled eggs in a dish. 4. Cover with mash and cheese; bake for 30-40 mins at 200C.', 'https://www.themealdb.com/images/media/meals/spswqs1511558697.jpg', 'Potatoes, Butter, Milk, Gruyere, Leek, Plain Flour, White Wine, Parsley, Salmon, Haddock, Smoked Haddock, Eggs', '1kg, Knob, Dash, 50g, 2 sliced, 75g, 150ml, 2 tbs chopped, 250g, 250g, 250g, 6', 'https://www.youtube.com/watch?v=Ds1Jb8H5Sg8'),
(53205, 'Thai prawn curry', 'Seafood', 'Thai', '1. Sauté onion and ginger, then stir in curry paste. 2. Add tomatoes and coconut cream; simmer for 5 mins. 3. Add prawns and cook for 5-10 mins until done. 4. Serve with rice and coriander.', 'https://www.themealdb.com/images/media/meals/qqlwv91763501559.jpg', 'Vegetable Oil, Onion, Ginger, Thai Red Curry Paste, Tinned Tomatos, Coconut Cream, Raw Frozen Prawns, Coriander', '1 tbls, 1 chopped, 1 tsp, 2 tsp, 400g, 50g, 400g, Chopped', 'https://www.youtube.com/watch?v=dEMPVKQXSYA'),
(53195, 'Thai curry noodle soup', 'Seafood', 'Thai', '1. Cook curry paste in oil for 1 min. 2. Add stir-fry veg and prawns; cook for 3 mins. 3. Add coconut milk, stock, and noodles. 4. Simmer for 5 mins until noodles are tender. 5. Garnish with herbs, chilli, and spring onion.', 'https://www.themealdb.com/images/media/meals/118oj61763423896.jpg', 'Vegetable Oil, Thai Green Curry Paste, Stir-fry Vegetables, Raw King Prawns, Coconut Milk, Vegetable Stock, Udon Noodles, Coriander, Basil, Red Chilli, Spring Onions', '1 teaspoon, 1 tbsp, 220g, 150g, 150ml, 225ml, 250g, 10g, 10g, 1 sliced, 1 sliced', 'https://www.youtube.com/watch?v=FN8tcugjCFs'),
(53065, 'Sushi', 'Seafood', 'Japanese', '1. Pat rice onto nori sheet. 2. Spread mayo and add fillings like tuna and cucumber. 3. Roll tightly using a mat. 4. For pressed sushi, layer salmon and rice in a tin and press down. 5. For sushi balls, twist rice and toppings in cling film.', 'https://www.themealdb.com/images/media/meals/g046bb1663960946.jpg', 'Sushi Rice, Rice wine, Caster Sugar, Mayonnaise, Rice wine, Soy Sauce, Cucumber', '300ml, 100ml, 2 tbs, 3 tbs, 1 tbs, 1 tbs, 1', 'https://www.youtube.com/watch?v=ub68OxEypaY'),
(53102, 'Squid, chickpea & chorizo salad', 'Seafood', 'Australian', '1. Char peppers, peel, and slice. 2. Mix peppers with chickpeas, parsley, chilli, and garlic. 3. Stir-fry squid for 30 secs, add chorizo for another 30 secs. 4. Combine all ingredients with oil, lemon juice, and zest.', 'https://www.themealdb.com/images/media/meals/wsu0rc1761848482.jpg', 'Red Pepper, Can of chickpeas, Parsley, Red Chilli, Garlic Clove, Olive Oil, Squid, Chorizo, Lemon', '4, 2 400g Cans, Bunch, 1, 2, 100 ml, 600g, 200g, Juice/zest of one', 'https://www.youtube.com/watch?v=ub68OxEypaY'),
(53248, 'Salmon noodle wraps', 'Seafood', 'Vietnamese', '1. Soak noodles in boiling water for 2 mins; drain. 2. Mix noodles with spring onions, peas, seasoning, and butter. 3. Place noodle mix on parchment, top with salmon and butter. 4. Seal parcels and bake at 200C for 15-20 mins.', 'https://www.themealdb.com/images/media/meals/prrirc1763781360.jpg', 'Rice Noodles, Spring Onions, Petit Pois, Chilli, Coriander, Lime, Salmon', '100g, 3 sliced thinly, 50g, 85g, 85g, 85g, 300g', 'https://www.youtube.com/watch?v=9j2qftITN-Y'),
(53234, 'Salmon noodle soup', 'Seafood', 'Vietnamese', '1. Boil stock and stir in curry paste. 2. Add noodles and cook for 8 mins. 3. Add mushrooms and corn; cook for 2 mins. 4. Add salmon and cook for 3 mins. 5. Stir in lime juice, soy sauce, and sugar before serving.', 'https://www.themealdb.com/images/media/meals/ikizdm1763760862.jpg', 'Chicken Stock, Thai Red Curry Paste, Rice Noodles, Shiitake Mushrooms, Sweetcorn, Salmon, Lime, Soy Sauce, Brown Sugar, Coriander', '1 L, 2 tsp, 100g, 150g, 125g, 2, Juice of 2, 1 tablespoon, Pinch, Bunch', 'https://www.youtube.com/watch?v=__Kh1sizUAM'),
(53377, 'Napa Cabbage with Dried Shrimp', 'Seafood', 'Chinese', '1. Rehydrate dried shrimp in boiling water for 30 mins, then drain. 2. Cut cabbage into 1-inch pieces, separating whites and greens. 3. Heat oil in a wok; stir-fry scallions, ginger, and shrimp for 1 min. 4. Add white cabbage parts and stir-fry for 3-4 mins. 5. Add green leaves and cook for 2 mins. 6. Stir in soy sauce, water, and cornstarch slurry to thicken. 7. Season with salt and pepper.', 'https://www.themealdb.com/images/media/meals/9nh4dl1766435484.jpg', 'Dried Shrimp, Boiling Water, Napa Cabbage, Peanut Oil, Scallions, Ginger, Soy Sauce, Water, Cornstarch, Kosher Salt, Pepper', '2 tablespoons, 3/4 cup, 1 head, 2 tablespoons, 4 Chopped, 1 tablespoon, 1 tablespoon, 1 tablespoon, 2 tsp, 1 tsp, 1/2 tsp', 'https://www.youtube.com/watch?v=Fj0JALB4_5k'),
(53051, 'Nasi lemak', 'Seafood', 'Malaysian', '1. Simmer rice with coconut milk, water, ginger, salt, and bay leaf until cooked. 2. Boil, peel, and halve eggs; slice cucumber. 3. Fry peanuts and anchovies until crisp; set aside. 4. Sauté onion, garlic, and shallots; add chile paste and cook for 10 mins. 5. Stir in remaining anchovies, sugar, and tamarind; simmer until thick. 6. Serve rice topped with sauce, peanuts, anchovies, cucumber, and eggs.', 'https://www.themealdb.com/images/media/meals/wai9bw1619788844.jpg', 'Coconut Milk, Water, Ginger Paste, Ginger, Bay Leaf, Rice, Eggs, Cucumber, Peanuts, Anchovy Fillet, Vegetable Oil, Onion, Garlic, Shallots, Chilli Powder, Sugar, Tamarind Paste', '2 cups, 2 cups, 1/4 tsp, 1, 1, 2 cups, 4, 1, 1 cup, 4 oz, 2 tbs, 1, 3 cloves, 3, 2 tsp, 3 tbs, 1/3 cup', 'https://www.youtube.com/watch?v=IUIs4C86Ilo'),
(53245, 'Noodle bowl salad', 'Seafood', 'Vietnamese', '1. Soak noodles and sugar snaps in boiling water for 4 mins, then drain and cool under cold water. 2. Toss with sesame oil. 3. Whisk dressing ingredients (soy sauce, honey, lemon juice, oil, garlic, ginger). 4. Mix noodles with spring onions, coriander, and salmon. 5. Pour dressing over and toss to combine.', 'https://www.themealdb.com/images/media/meals/zry07j1763779321.jpg', 'Rice Noodles, Sugar Snap Peas, Sesame Seed Oil, Spring Onions, Coriander, Hot Smoked Flaked Salmon, Soy Sauce, Clear Honey, Lemon Juice, Ground Nut Oil, Garlic, Ginger', '125g, 200g, 2 tsp, 4 sliced, Handful, 150g, 3 tablespoons, 1 tablespoon, 1 tablespoon, 1 tablespoon, 1 clove, Knob', 'https://www.youtube.com/watch?v=7EAdKeikJ9o'),
(53191, 'Pad Thai', 'Seafood', 'Thai', '1. Soak noodles in boiling water for 4 mins, drain, and refresh with cold water. 2. Mix lime juice, cayenne, sugar, and fish sauce. 3. Fry prawns until warm; add spring onions and noodles. 4. Stir in the sauce, beansprouts, and half the peanuts/coriander. 5. Cook for 1 min and serve with extra peanuts, coriander, and lime wedges.', 'https://www.themealdb.com/images/media/meals/rg9ze01763479093.jpg', 'Rice Noodles, Lime, Cayenne Pepper, Muscovado Sugar, Fish Sauce, Vegetable Oil, Tiger Prawns, Spring Onions, Bean Sprouts, Peanuts, Coriander, Sweet chilli sauce', '125g, Juice of 3, 1/2 teaspoon, 2 teaspoons, 2 tablespoons, 2 tablespoons, 200g, 4 finely sliced, 140g, 25g, Handful, To serve', 'https://www.youtube.com/watch?v=F86GfZIph8o'),
(53169, 'Ajo blanco', 'Starter', 'Spanish', '1. Soak white bread in 350ml water for 10 mins. 2. Blend the soaked bread, almonds, garlic, vinegar, and olive oil with another 350ml water and 1 tsp salt until smooth. 3. Chill in the fridge for at least 1 hour. 4. Serve with a drizzle of oil and black pepper.', 'https://www.themealdb.com/images/media/meals/5jdtie1763289302.jpg', 'White bread, Almonds, Extra Virgin Olive Oil, Garlic Clove, Red Wine Vinegar', '150g, 200g, 50 ml, 1, 1 ½ tbsp', 'https://www.youtube.com/watch?v=AS2mSRtWyW0'),
(52842, 'Broccoli & Stilton soup', 'Starter', 'British', '1. Sauté onions in rapeseed oil until soft. 2. Add celery, leek, potato, and butter; cover and sweat for 5 mins. 3. Add stock and broccoli stalks; simmer for 10-15 mins. 4. Add broccoli florets and cook for 5 more mins. 5. Blend until smooth, then stir in Stilton cheese and season with pepper.', 'https://www.themealdb.com/images/media/meals/tvvxpv1511191952.jpg', 'Rapeseed Oil, Onion, Celery, Leek, Potatoes, Butter, Vegetable Stock, Broccoli, Stilton Cheese', '2 tblsp, 1 finely chopped, 1, 1 sliced, 1 medium, 1 knob, 1 litre hot, 1 Head chopped, 140g', 'https://www.youtube.com/watch?v=_HgVLpmNxTY'),
(53366, 'Beef and Broccoli Stir-Fry', 'Beef', 'Chinese', '1. Marinate beef in soy sauce, rice wine, cornstarch, and pepper for 10 mins. 2. Whisk sauce (oyster sauce, rice wine, soy sauce, broth). 3. Blanch broccoli for 2 mins; drain. 4. Stir-fry beef in a hot wok for 1 min, add garlic, then toss. 5. Add sauce, cornstarch slurry, and broccoli; stir until thickened.', 'https://www.themealdb.com/images/media/meals/m0p0j81765568742.jpg', 'Soy Sauce, Dry sherry, Cornstarch, Black Pepper, Sirloin steak, Oyster Sauce, Chicken Stock, Broccoli, High Heat Cooking Oil, Garlic, Water', '1 tsp, 1 tsp, 1/2 tsp, 1/8 teaspoon, 1 lb, 2 tablespoons, 1/4 cup, 1 lb, 2 tablespoons, 2 cloves minced, 1 tablespoon', 'https://www.youtube.com/watch?v=BBABeZjlRM8'),
(53230, 'Purple sprouting broccoli tempura with nuoc cham', 'Miscellaneous', 'Vietnamese', '1. Whisk nuoc cham ingredients (fish sauce, lime, chilli, sugar) with 5 tbsp hot water. 2. Whisk cornflour, plain flour, and salt; then whisk in soda water to make a batter. 3. Heat oil to 180C. 4. Dip broccoli in batter and fry for 2-3 mins until crisp. 5. Drain and serve with the dipping sauce.', 'https://www.themealdb.com/images/media/meals/xnv4wf1763756529.jpg', 'Corn Flour, Plain Flour, Sesame Seed, Vegetable Oil, Soda Water, Purple Sprouting Broccoli, Fish Sauce, Lime, Birds-eye Chillies, Sugar', '50g, 100g, 1 tablespoon, For frying, 250ml, 200g, 2 tablespoons, Juice of 2, 1 chopped, 2 tablespoons', ''),
(52993, 'Honey Balsamic Chicken with Crispy Broccoli & Potatoes', 'Chicken', 'American', '1. Roast potato wedges at 425F for 5 mins. 2. Add broccoli tossed in garlic oil and roast for another 15-20 mins. 3. Pan-fry chicken until cooked through; set aside. 4. In the same pan, simmer vinegar, honey, stock, and garlic until thick; stir in butter. 5. Coat chicken in glaze and serve with roasted veggies.', 'https://www.themealdb.com/images/media/meals/kvbotn1581012881.jpg', 'Potatoes, Broccoli, Garlic, Chicken Breast, Balsamic Vinegar, Honey, Chicken Stock, Butter, Vegetable Oil, Olive Oil', '5, 1, 2 cloves, 2, 1 tbsp, 1 tbsp, 1 tbsp, 1 tbsp, 1 tbsp, 1 tbsp', ''),
(52840, 'Clam chowder', 'Starter', 'American', '1. Boil clams in water for 2 mins until open; strain and reserve stock. 2. Fry bacon, then add onion, thyme, and bay leaf; cook until soft. 3. Stir in flour, then gradually add clam stock, milk, and cream. 4. Add potatoes and simmer for 10 mins. 5. Stir in clam meat and parsley before serving.', 'https://www.themealdb.com/images/media/meals/rvtvuw1511190488.jpg', 'Clams, Butter, Bacon, Onion, Thyme, Bay Leaf, Plain Flour, Milk, Double Cream, Potatoes, Parsley', '1½ kg, 50g, 150g, 1 finely chopped, sprigs, 1, 1 tbls, 150ml, 150ml, 2 medium, Chopped', 'https://www.youtube.com/watch?v=fEN_fm6kX6k'),
(52779, 'Cream Cheese Tart', 'Starter', 'American', '1. Make dough from flour, butter, egg, and salt; chill in a tart form. 2. Blend cream cheese, milk, eggs, parmesan, and nutmeg. 3. Pour filling into crust and bake at 175C for 25 mins. 4. Marinate tomatoes in oil, vinegar, and honey. 5. Top the baked tart with tomatoes and basil.', 'https://www.themealdb.com/images/media/meals/wurrux1468416624.jpg', 'Flour, Butter, Egg, Salt, Cheese, Milk, Eggs, Parmesan Cheese, Plum tomatoes, White Vinegar, Honey, Basil', '250g, 125g, 1, Pinch, 300g, 100ml, 3, 100g, 350g, 3tbsp, 1 tbsp, Topping', 'https://www.youtube.com/watch?v=UhQPwO4uymo'),
(52841, 'Creamy Tomato Soup', 'Starter', 'British', '1. Fry onions, celery, carrots, and potatoes with bay leaves for 15 mins. 2. Add tomato puree, sugar, vinegar, tomatoes, passata, and stock; simmer for 15 mins. 3. Remove bay leaves and blend until smooth. 4. Reheat while stirring in milk (do not boil). 5. Serve with cheesy sausage rolls.', 'https://www.themealdb.com/images/media/meals/stpuws1511191310.jpg', 'Olive Oil, Onions, Celery, Carrots, Potatoes, Bay Leaf, Tomato Puree, Sugar, White Vinegar, Chopped Tomatoes, Passata, Vegetable Stock Cube, Whole Milk', '3 tbsp, 2 chopped, 2 sticks, 300g, 500g, 4, 5 tblsp, 2 tblsp, 2 tblsp, 1½ kg, 500g, 3, 400ml', 'https://www.youtube.com/watch?v=lBhwjjUiFk4'),
(53173, 'Quick gazpacho', 'Starter', 'Spanish', '1. In a blender, combine passata, red pepper, chilli, garlic, sherry vinegar, and lime juice. 2. Blend until completely smooth. 3. Season to taste with salt and pepper. 4. Serve immediately with ice cubes for a refreshing cold starter.', 'https://www.themealdb.com/images/media/meals/h5qmn31763304965.jpg', 'Passata, Red Pepper, Red Chilli, Garlic, Sherry vinegar, Lime', '250g, 1 chopped, 1 chopped, 1 clove, 1 teaspoon, Juice of 1/2', 'https://www.youtube.com/watch?v=sJzHIxlDTHc'),
(53150, 'Padron peppers', 'Vegan', 'Spanish', '1. Heat olive oil in a large frying pan over high heat. 2. Fry peppers, stirring frequently for 5 mins until blistered and wilted. 3. Transfer to a plate and season with sea salt. 4. Serve with dips or as part of a tapas spread.', 'https://www.themealdb.com/images/media/meals/0ljvc51763248075.jpg', 'Olive Oil, Padron peppers', '1 tablespoon, 500g', 'https://www.youtube.com/watch?v=wD6NE3cMKBY'),
(53115, 'Red onion pickle', 'Vegan', 'Norwegian', '1. Peel and slice onions into half-moons; brine with salt in a colander for 1 hour. 2. Simmer vinegar, water, and sugar in a pan until sugar dissolves. 3. Pack onions into jars with pepper. 4. Cover with warm vinegar, add bay leaves, and seal. Keep in fridge for up to 4 weeks.', 'https://www.themealdb.com/images/media/meals/ppodrp1762325183.jpg', 'Red Onions, Sea Salt, Cider Vinegar, Granulated Sugar, Black Pepper, Bay Leaves', '3 Large, 2 tsp, 200ml, 50g, 1 tsp, 4', 'https://www.youtube.com/watch?v=3z2jTcsL28g'),
(52941, 'Roast fennel and aubergine paella', 'Vegan', 'Spanish', '1. Roast fennel, aubergine, pepper, and courgette with oil and salt at 200C for 20 mins. 2. Sauté onion, then stir in rice, paprika, saffron, and white wine. 3. Add two-thirds of the stock and simmer for 10 mins. 4. Stir in peas and roasted veg, add remaining stock and lemon wedges; cook for 10 more mins. 5. Garnish with parsley.', 'https://www.themealdb.com/images/media/meals/1520081754.jpg', 'Baby Aubergine, Fennel, Red Pepper, Courgettes, Onion, Paella Rice, Paprika, Saffron, White Wine, Vegetable Stock, Frozen Peas, Lemon, Parsley, Salt, Black Pepper', '6 small, 4 small, 1 thinly sliced, 1 medium, 1 finely chopped, 300g, 1 tsp, pinch, 200ml, 700ml, 100g, 1 chopped, Handful, pinch, pinch', 'https://www.youtube.com/watch?v=H5SmjR-fxUs'),
(53250, 'Vegan banh mi', 'Vegan', 'Vietnamese', '1. Pickle shredded veg with vinegar, sugar, and salt. 2. Toast baguette pieces at 180C for 5 mins. 3. Spread hummus on baguette, top with tempeh and pickled veg. 4. Garnish with herbs and hot sauce.', 'https://www.themealdb.com/images/media/meals/sonirb1763782831.jpg', 'Raw Vegetables, Vegan White Wine Vinegar, Golden Caster Sugar, Baguette, Hummus, Tempeh, Coriander, Mint, Hotsauce', '150g, 3 tablespoons, 1 tsp, 1 large, 100g, 175g, Handful, Handful, To serve', 'https://www.youtube.com/watch?v=i0_C3eRTbgg'),
(52794, 'Vegan Chocolate Cake', 'Vegan', 'American', '1. Mix all dry ingredients (flour, sugar, cacao, baking powder) with wet ingredients (flax eggs, almond milk, vanilla, boiling water). 2. Blend until smooth. 3. Bake at 180C for 45 mins. 4. Decorate with melted vegan chocolate.', 'https://www.themealdb.com/images/media/meals/qxutws1486978099.jpg', 'Self-raising Flour, coco sugar, cacao, baking powder, flax eggs, almond milk, vanilla, water', '1 1/4 cup, 1/2 cup, 1/3 cup raw, 1 tsp, 2, 1/2 cup, 1 tsp, 1/2 cup boiling', 'https://www.youtube.com/watch?v=C3pAgB7pync'),
(52775, 'Vegan Lasagna', 'Vegan', 'Italian', '1. Boil vegetables for 5-7 mins; add lentils and simmer for 20 mins until soft. 2. Blanch spinach and cook lasagne sheets separately. 3. Make white sauce by melting butter, adding flour, and whisking in soya milk, mustard, and vinegar. 4. Assemble layers in a dish and bake at 180C for 25 mins.', 'https://www.themealdb.com/images/media/meals/rvxxuy1468312893.jpg', 'green red lentils, Carrots, onion, zucchini, coriander, spinach, lasagne sheets, vegan butter, flour, soya milk, mustard, vinegar', '1 cups, 1, 1, 1 small, sprinking, 150g, 10, 35g, 4 tablespoons, 300ml, 1.5 teaspoons, 1 teaspoon', 'https://www.youtube.com/watch?v=VU8cXvlGbvc'),
(53373, 'Air Fryer Egg Rolls', 'Side', 'Chinese', '1. Cook ground meat with olive oil for 6-8 mins. 2. Add garlic, ginger, carrot, scallions, and cabbage; cook until soft. 3. Season with soy sauce and rice vinegar. 4. Wrap filling in egg roll wrappers and seal with water. 5. Air fry at 350F for 6-7 mins, flip, and cook for another 4-5 mins until crispy.', 'https://www.themealdb.com/images/media/meals/grhn401765687086.jpg', 'Olive Oil, Ground Pork, Garlic, Ginger, Carrots, Scallions, Cabbage, Soy Sauce, Rice Vinegar, Egg Roll Wrappers, Oil', '1 tablespoon, 1 lb, 1 clove peeled crushed, 1 tablespoon, 1 medium, 3 chopped, 3 Cups, 1 tablespoon, 1 tablespoon, 12, For brushing', 'https://www.youtube.com/watch?v=XnA-wcVb4l0'),
(53282, 'Algerian Carrots', 'Side', 'Algerian', '1. Steam sliced carrots for 4-6 mins; reserve 1/2 cup liquid. 2. Sauté salt, pepper, cinnamon, cumin, garlic, and thyme in olive oil for 10 mins. 3. Add reserved liquid and bay leaf; simmer for 20 mins. 4. Toss in carrots and cook for 2-3 mins. 5. Finish with lemon juice.', 'https://www.themealdb.com/images/media/meals/o2cd4r1764113576.jpg', 'Water, Carrots, Olive Oil, Salt, Black Pepper, Ground Cinnamon, Ground Cumin, Garlic, Thyme, Bay Leaf, Lemon Juice', '1 1/2 cup, 2 Lbs, 5 tablespoons, 1 tsp, 1/2 teaspoon, 1/2 teaspoon, 1/2 teaspoon, 3 Cloves Crushed, 1/2 teaspoon, 1, 1 tsp', 'https://www.youtube.com/watch?v=mF2ND56szUQ'),
(53332, 'Venezuelan turnovers', 'Side', 'Venezulan', '1. Cook ground beef with onion, pepper, garlic, capers, tomato sauce, and Sazón for 20 mins. 2. Roll dough balls into 5-inch circles. 3. Place filling on one half, fold into a semi-circle, and seal edges. 4. Fry in hot oil until lightly browned on both sides. 5. Drain on paper towels.', 'https://www.themealdb.com/images/media/meals/zjtfp31764440795.jpg', 'Ground Beef, Pepper, Ground Cumin, Vegetable Oil, Onion, Green Pepper, Red Pepper, Garlic Powder, Capers, Tomato Sauce, Sazon, Yellow Masarepa, Vegetable Oil', '450g, Pinch, Pinch, 1 tablespoon, 1 cup, 1/2 cup, 1/2 cup, 1 tsp, 1/4 cup, 1 Can, 1 Can, 2, For frying', 'https://www.youtube.com/watch?v=OfuQf6sCycU'),
(53378, 'Sesame Cucumber Salad', 'Side', 'Chinese', '1. Peel cucumbers, quarter them lengthwise, and cut into 1/2-inch pieces. 2. Place in a bowl and sprinkle with salt. 3. Toss with sesame oil, rice vinegar, basil, and chili flakes. 4. Top with toasted sesame seeds and serve.', 'https://www.themealdb.com/images/media/meals/93iok31766436070.jpg', 'Cucumber, Salt, Sesame Seed Oil, Rice Vinegar, Basil Leaves, Red Chilli Flakes, Sesame Seed', '2 medium, 1/2 tsp, 2 tsp, 2 tablespoons, 6, 1/2 tsp, 2 tsp', 'https://www.youtube.com/watch?v=q37qn81lg5c'),
(53299, 'Polish patties (kotlety)', 'Side', 'Polish', '1. Soak bread roll in milk; fry onions until golden. 2. Mix beef, egg, garlic, marjoram, and fried onions. 3. Squeeze milk from bread and add to mixture; season well. 4. Form 8 patties and coat in breadcrumbs. 5. Fry in oil for 6-7 mins per side until browned.', 'https://www.themealdb.com/images/media/meals/vvn5f71764360273.jpg', 'Bread Rolls, Milk, Onion, Vegetable Oil, Ground Beef, Egg, Garlic Clove, Marjoram, Breadcrumbs', '1, 120ml, 1 chopped, 100 ml, 500g, 1, 1, Pinch, 75g', 'https://www.youtube.com/shorts/0XrToCi-U1c'),
(53038, 'Mustard champ', 'Side', 'Irish', '1. Boil potatoes for 15 mins until tender, drain and mash. 2. Heat milk and half the butter, then beat into the mash with wholegrain mustard. 3. Fry spring onions in remaining butter for 2 mins until soft. 4. Fold onions into the mash and serve.', 'https://www.themealdb.com/images/media/meals/o7p9581608589317.jpg', 'Potatoes, Milk, Butter, Mustard, Spring Onions', '1kg, 200ml, 50g, 2 tbs, Bunch', 'https://www.youtube.com/watch?v=_iKllHSC978'),
(52978, 'Kumpir', 'Side', 'Turkish', '1. Mash butter and cheese into a baked potato. 2. Finely chop onion and red pepper. 3. Mix ingredients in a bowl with salt, pepper, and optional chili flakes. 4. Stuff the potato with the mixture and add desired toppings like sweetcorn or olives.', 'https://www.themealdb.com/images/media/meals/mlchx21564916997.jpg', 'Potatoes, Butter, Cheese, Onion, Red Pepper, Red Chilli Flakes', '2 large, 2 tbs, 150g, 1 large, 1 large, Pinch', 'https://www.youtube.com/watch?v=IEDEtZ4UVtI'),
(53033, 'Japanese gohan rice', 'Side', 'Japanese', '1. Rinse and massage rice in cold water about 5-6 times until water is clear. 2. Combine rice with 400ml water (or dashi mix) in a pan. 3. Bring to boil, then simmer covered for 15 mins. 4. Let it sit off heat for 15 mins, stir in mirin, and serve.', 'https://www.themealdb.com/images/media/meals/kw92t41604181871.jpg', 'Sushi Rice, Mirin, Pickle Juice, Spring Onions', '300g, 1 tbs, Garnish, Garnish', 'https://www.youtube.com/watch?v=rZO86_-MIp0'),
(53364, 'Jamaican Steamed Cabbage', 'Side', 'Jamaican', '1. Add all ingredients to a large pan over medium heat and cover. 2. Cook for 10 minutes, stirring occasionally. 3. Reduce heat to low and cook for another 5 minutes until cabbage is tender. 4. Remove thyme stalks before serving.', 'https://www.themealdb.com/images/media/meals/paejva1765321314.jpg', 'Cabbage, Carrots, Plum Tomatoes, Onion, Garlic, Spring Onions, Thyme, Scotch Bonnet, Water, Olive Oil, Unsalted Butter, Kosher Salt, Black Pepper', '1/2, 2 sliced, 1 chopped, 1 chopped, 4 Cloves Chopped, 4 Chopped, 4 sprigs, 1/2, 2 tablespoons, 2 tablespoons, 4 tablespoons, 2 tsp, 1 tsp', 'https://www.youtube.com/watch?v=amEkrC9rzgM'),
(53256, 'Cacik', 'Side', 'Turkish', '1. Strain yogurt through muslin in the fridge for 12 hours. 2. Mix lemon juice, olive oil, and dried mint; then stir in the strained yogurt. 3. Grate cucumber, squeeze out all liquid, and add to the mix with minced garlic and salt. 4. Garnish with olive oil and extra mint.', 'https://www.themealdb.com/images/media/meals/16zbeu1763789342.jpg', 'Natural Yoghurt, Lemon Juice, Extra Virgin Olive Oil, Dried Mint, Cucumber, Garlic', '500g, 2 tsp, 1 tablespoon, 1 tablespoon, 1, 2 cloves minced', 'https://www.youtube.com/watch?v=eIDgcvpAvf8'),
(53284, 'Algerian Bouzgene Berber Bread with Roasted Pepper Sauce', 'Side', 'Algerian', '1. Roast peppers and tomatoes under broiler for 8 mins, peel and core. 2. Sauté jalapenos and garlic in olive oil, then mix with roasted veg and chop to a coarse consistency. 3. Mix semolina, salt, and olive oil with water to form a dough; divide into 6 balls. 4. Roll out and fry in a hot skillet with olive oil until dark spots appear. 5. Serve bread by breaking pieces and scooping into the sauce.', 'https://www.themealdb.com/images/media/meals/se5vhk1764114880.jpg', 'Red Pepper, Tomato, Olive Oil, Garlic, Jalapeno, Salt, Semolina, Water', '2, 4, 11 tablespoons total, 4 Cloves Chopped, 1 chopped, To taste, 2 Lbs, 3 Cups', ''),
(52925, 'Split Pea Soup', 'Side', 'Canadian', '1. Boil gammon, drain water, then refill and boil again to reduce salt. 2. Add all ingredients except frozen peas and simmer for 1.5-2.5 hours. 3. Shred ham once tender. 4. Blend soup with frozen peas until smooth. 5. Stir in ham and serve with crusty bread.', 'https://www.themealdb.com/images/media/meals/xxtsvx1511814083.jpg', 'Ham, Peas, Onions, Carrots, Bay Leaves, Celery, Frozen Peas, Bread', '1kg, 200g, 2 chopped, 2 chopped, 2, 1 chopped, 300g, to serve', 'https://www.youtube.com/watch?v=qdhWz7qAaCU'),
(52981, 'Snert (Dutch Split Pea Soup)', 'Side', 'Dutch', '1. Boil water, split peas, pork, and bouillon for 45 mins. 2. Remove pork, debone, and slice. 3. Add celery, carrots, potato, onion, leek, and celeriac; simmer for 30 mins. 4. Add sausage for the last 15 mins. 5. Purée soup if desired, return meat to the pot, and garnish with sausage slices.', 'https://www.themealdb.com/images/media/meals/9ptx0a1565090843.jpg', 'Water, Peas, Pork, Vegetable Stock Cube, Celery, Carrots, Potatoes, Onion, Leek, Celeriac, Sausages', '2L, 300g, 100g, 1, 2, 2, 1 large, 1 small, 1 small, 1 cup, 1 pound', 'https://www.youtube.com/watch?v=5YV0sJLtLt8'),
(53222, 'Vegetarian Shakshuka', 'Vegetarian', 'Saudi Arabian', '1. Fry onion and pepper until soft. 2. Add garlic granules and cook for a minute. 3. Stir in chopped tomatoes and remaining spices; simmer for 20 mins. 4. Make indents in the sauce and crack an egg into each. 5. Cook until egg whites are set, garnish and serve with toast.', 'https://www.themealdb.com/images/media/meals/eo0yfb1763600916.jpg', 'Red Onions, Red Pepper, Tomato, Cumin, Garlic Granules, Cayenne Pepper, Paprika, Egg, Parsley, Chilli Flakes, Toast', '1/2, 1/2, 400g, 1/2 tsp, 1/2 tsp, 1/2 tsp, 1 tsp, 2, Garnish, Garnish, 2 sliced', 'https://www.youtube.com/watch?v=ZNEos6ybryg'),
(53241, 'Vietnamese veg parcels', 'Vegetarian', 'Vietnamese', '1. Soak rice pancakes and noodles until tender; cut noodles into 2cm strips. 2. Arrange noodles, chicken, vegetables, and herbs on a pancake and roll up like a cigar. 3. Mix dipping sauce ingredients. 4. Serve rolls wrapped in lettuce leaves with herbs and dunk into the sauce.', 'https://www.themealdb.com/images/media/meals/f698g91763768731.jpg', 'Rice Flour Pancakes, Rice Noodles, Chicken Breast, Carrots, Cucumber, Red Pepper, Lettuce, Coriander, Mint, Fish Sauce, Rice Vinegar, Lime, Red Chilli', '100g, 50g, 1, 1 sliced, 1 sliced, 1 sliced, To serve, To serve, To serve, 4 tbsp, 2 tbsp, Juice of 1/2, 1 sliced', 'https://www.youtube.com/watch?v=k3ciVdNBuK0'),
(53240, 'Tofu, greens & cashew stir-fry', 'Vegetarian', 'Vietnamese', '1. Fry broccoli in oil on high heat for 5 mins until tender. 2. Add garlic and chilli, fry for 1 min. 3. Toss in spring onions, soya beans, pak choi, and tofu; stir-fry for 2-3 mins. 4. Add hoisin, soy sauce, and cashews to warm through before serving.', 'https://www.themealdb.com/images/media/meals/minfsc1763766806.jpg', 'Vegetable Oil, Broccoli, Garlic Clove, Red Chilli, Spring Onions, Soya Bean, Pak Choi, Marinated Tofu, Hoisin Sauce, Soy Sauce, Cashew Nuts', '1 tbsp, 1 head, 4 sliced, 1 sliced, 1 bunch, 140g, 2 heads, 300g, 1.5 tbsp, 1 tbsp, 25g', 'https://www.youtube.com/watch?v=l8wuWeNy3J4'),
(53203, 'Thai rice noodle salad', 'Vegetarian', 'Thai', '1. Soak noodles and beansprouts in boiling water for 4 mins, then drain and cool. 2. Mix lime zest/juice, fish/soy sauce, and sugar; stir into noodles with red onion and lettuce. 3. Optional: Add stir-fried minced pork or sliced sesame-crusted sirloin steak. 4. Garnish with chilli and mint leaves.', 'https://www.themealdb.com/images/media/meals/6g3rso1763486069.jpg', 'Vermicelli Rice Noodles, Bean Sprouts, Lime, Fish Sauce, Muscovado Sugar, Red Onions, Lettuce, Minced Pork, Ginger, Cayenne Pepper, Sunflower Oil, Sesame Seed, Sirloin steak, Red Chilli', '1/2 bag, 200g, Zest and juice of 2, 2-3 tbsp, 1 tsp, 1 sliced, 2 small, 500g, Knob, Pinch, 1 tsp, 2 tbsp, 4, 1 sliced', '');
INSERT INTO `recipes` (`id`, `name`, `category`, `area`, `instructions`, `thumbnail`, `all_ingredients`, `all_measures`, `youtube`) VALUES
(53246, 'Tangy carrot, cabbage & onion salad', 'Vegetarian', 'Vietnamese', '1. Mix sliced carrots, cabbage, and onions in a bowl. 2. Whisk together lime juice, oil, chilli, and sugar for the dressing. 3. Pour dressing over the vegetables and toss. 4. Mix in fresh herbs and top with roasted peanuts.', 'https://www.themealdb.com/images/media/meals/dbazbg1763779999.jpg', 'Carrots, Red Cabbage, Red Onions, Mint, Coriander Leaves, Roasted Peanut, Lime, Ground Nut Oil, Red Chilli, Brown Sugar', '4 sliced, 1/2, 2 sliced, Handful, Handful, Handful, Juice of 2, 1 tbsp, 1 chopped, 1 tbsp', 'https://www.youtube.com/watch?v=-BJWMkJMIns'),
(52911, 'Summer Pistou', 'Vegetarian', 'French', '1. Fry leeks and courgette in oil for 5 mins. 2. Add stock, 3/4 of cannellini beans, green beans, and half the tomatoes; simmer for 5-8 mins. 3. Blitz remaining beans, tomatoes, garlic, and basil until smooth; stir in Parmesan. 4. Stir the basil sauce into the soup and cook for 1 min before serving.', 'https://www.themealdb.com/images/media/meals/rqtxvr1511792990.jpg', 'Rapeseed Oil, Leek, Courgettes, Vegetable Stock, Cannellini Beans, Green Beans, Tomatoes, Garlic Clove, Basil, Parmesan', '1 tbs, 2 finely chopped, 1 large, 1L, 400g, 200g, 3 chopped, 3 chopped, Small pack, 40g', 'https://www.youtube.com/watch?v=fyeqZJKEXp0'),
(52817, 'Stovetop Eggplant With Harissa, Chickpeas, and Cumin Yogurt', 'Vegetarian', 'American', '1. Brown eggplants in oil on medium heat for 20 mins until soft. 2. Mix harissa, chickpeas, and tomatoes; add to eggplants and cook for 5 mins. 3. Mix yogurt with cumin. 4. Garnish eggplant with parsley and olive oil, serving the cumin yogurt on the side.', 'https://www.themealdb.com/images/media/meals/yqwtvu1487426027.jpg', 'Olive Oil, Egg Plants, Harissa Spice, Chickpeas, Cherry Tomatoes, Greek yogurt, Ground cumin, Parsley', '4 tablespoons, 6 small, 1/2 tablespoon, 1 can, 2 cups halved, 1 1/2 cups, 1 tablespoon, 1/2 cup', 'https://www.youtube.com/watch?v=uYB-1xJp4lg'),
(52849, 'Spinach & Ricotta Cannelloni', 'Vegetarian', 'Italian', '1. Simmer garlic, sugar, vinegar, and tomatoes for 20 mins; add basil and place in dishes. 2. Mix mascarpone and milk. 3. Wilt spinach, squeeze out water, chop, and mix with 100g Parmesan, ricotta, and nutmeg. 4. Pipe filling into tubes, top with mascarpone sauce, mozzarella, and Parmesan; bake at 200C for 30-35 mins.', 'https://www.themealdb.com/images/media/meals/wspuvp1511303478.jpg', 'Olive Oil, Garlic, Caster Sugar, Red Wine Vinegar, Chopped Tomatoes, Basil Leaves, Mascarpone, Milk, Parmesan, Mozzarella, Spinach, Ricotta, Nutmeg, Cannellini Beans', '3 tbsp, 8 cloves, 3 tbsp, 2 tbsp, 3 400g Cans, Bunch, 2 tubs, 3 tbsp, 85g, 2 sliced, 1kg, 3 tubs, pinch, 400g', 'https://www.youtube.com/watch?v=rYGaEJjyLQA'),
(53166, 'Chickpea, chorizo & spinach stew', 'Pork', 'Spanish', '1. Fry onion, carrot, celery, and herbs. 2. Add garlic, chorizo, cinnamon, and paprika; fry until chorizo releases oil. 3. Stir in chickpeas, vinegar, and water; simmer for 2 mins. 4. Stir in spinach until wilted and serve with crusty bread.', 'https://www.themealdb.com/images/media/meals/xvnx8j1763287209.jpg', 'Extra Virgin Olive Oil, Onion, Carrots, Celery, Thyme, Bay Leaves, Garlic, Chorizo, Cinnamon, Paprika, Chickpeas, Sherry vinegar, Spinach', '4 tablespoons, 1 chopped, 1 Diced, 1 Diced, 3, 2, 2 cloves, 200g, 1/4 tsp, 1 tsp, 800g, 2 tbsp, 400g', 'https://www.youtube.com/watch?v=nI2Sm4B3gWU'),
(52771, 'Spicy Arrabiata Penne', 'Vegetarian', 'Italian', '1. Boil pasta for 9 mins. 2. Sauté garlic in olive oil, add chopped tomatoes, chilli flakes, and Italian seasoning; boil for 5 mins. 3. Stir in fresh basil. 4. Toss drained pasta with sauce and garnish with Parmigiano-Reggiano.', 'https://www.themealdb.com/images/media/meals/ustsqw1468250014.jpg', 'penne rigate, olive oil, garlic, chopped tomatoes, red chilli flakes, italian seasoning, basil, Parmigiano-Reggiano', '1 pound, 1/4 cup, 3 cloves, 1 tin, 1/2 teaspoon, 1/2 teaspoon, 6 leaves, sprinkling', 'https://www.youtube.com/watch?v=1IszT_guI08'),
(52872, 'Spanish Tortilla', 'Vegetarian', 'Spanish', '1. Slow-cook onion in oil and butter for 15 mins. 2. Add potatoes and cook for 20 mins. 3. Stir in garlic and beaten eggs; cook covered for 20 mins. 4. Flip using a plate to finish the other side. 5. Serve with garlic-rubbed tomato baguette.', 'https://www.themealdb.com/images/media/meals/quuxsx1511476154.jpg', 'Onion, Olive Oil, Butter, Potatoes, Garlic, Eggs, Parsley, Baguette, Vine Tomatoes', '1 sliced, 4 tbsp, 25g, 400g, 6 cloves, 8, Handful, 1, 4', 'https://www.youtube.com/watch?v=JceGMNG7rpU'),
(53384, 'Silken Tofu with Sesame Soy Sauce', 'Vegetarian', 'Chinese', 'Prepare the tofu: Drain the tofu and gently remove it from its packaging onto a large plate. Carefully slice the tofu into 1/2-inch slabs widthwise. Garnish with toppings and serve: Drizzle the soy sauce and sesame sauce on top. Then garnish it with scallions and sesame seeds, and serve.', 'https://www.themealdb.com/images/media/meals/j9nray1765657692.jpg', 'Silken Tofu, Soy Sauce, Chinese Sesame Sauce, Scallions, Sesame Seed', '16 ounces, 3 tablespoons, 2 tablespoons, 1 sliced, 2 tsp', 'https://www.youtube.com/shorts/bSLv5vFn5Z0'),
(53385, 'Sichuan Eggplant', 'Vegetarian', 'Chinese', 'Quarter the eggplant lengthwise and chop into large batons. Mix chicken stock, sugar, and soy sauce. Mix chili bean paste, garlic, ginger, and sichuan peppercorns. Sauté eggplant in oil until brown. Add paste mixture, then stock mixture, then cornstarch slurry. Finally, add scallions and vinegar. Garnish with cilantro.', 'https://www.themealdb.com/images/media/meals/1oz4nb1765687990.jpg', 'Egg Plants, Peanut Oil, Chicken Stock, Sugar, Soy Sauce, Chilli Bean Paste, Sichuan Pepper, Ginger, Garlic, Cornstarch, Apple Cider Vinegar, Scallions, Cilantro', '1.5 pounds sliced, 2 tablespoons, 1/4 cup, 2 tsp, 1/2 tsp, 1 ½ tbsp, 2 tsp, 2 tsp, 5 cloves, 1 tsp, 2 tsp, 4 Chopped, Garnish', 'https://www.youtube.com/watch?v=j54Af9gBmzo'),
(53386, 'Shakshuka', 'Vegetarian', 'Egyptian', 'Heat oil, soften onions, chilli, garlic and coriander stalks. Stir in tomatoes and sugar, bubble until thick. Make 4 dips in the sauce, crack an egg into each. Cook covered for 6-8 mins. Scatter with coriander and serve.', 'https://www.themealdb.com/images/media/meals/g373701551450225.jpg', 'Olive Oil, Red Onions, Red Chilli, Garlic, Coriander, Cherry Tomatoes, Caster Sugar, Eggs, Feta', '1 tbs, 2 chopped, 1 finely chopped, 1 clove, Chopped, 800g, 1 tbs, 4, Spinkling', 'https://www.youtube.com/watch?v=C-3_jYrfdBU'),
(53387, 'Vegetarian Shakshuka', 'Vegetarian', 'Saudi Arabian', 'Fry onion and pepper. Add garlic granules. Add chopped tomatoes and spices, simmer for 20 mins. Make indents, crack eggs. Garnish and serve with toast.', 'https://www.themealdb.com/images/media/meals/eo0yfb1763600916.jpg', 'Red Onions, Red Pepper, Tomato, Cumin, Garlic Granules, Cayenne Pepper, Paprika, Egg, Parsley, Chilli Flakes, Toast', '1/2, 1/2, 400g, 1/2 teaspoon, 1/2 tsp, 1/2 teaspoon, 1 tsp, 2, Garnish, Garnish, 2 sliced', 'https://www.youtube.com/watch?v=ZNEos6ybryg'),
(53388, 'Shakshuka Feta Cheese', 'Miscellaneous', 'Saudi Arabian', 'Heat oil, add onions, garlic, celery and red pepper. Add cumin, salt, pepper and tomato sauce. Add eggs, cover and cook. Add fresh spinach and feta cheese at the end.', 'https://www.themealdb.com/images/media/meals/wpkfin1763597958.jpg', 'Egg, Tomato Sauce, Olive Oil, Shallots, Celery, Garlic, Spinach, Feta, Red Pepper, Ground Cumin, Salt, Black Pepper', '4 large, 3 tablespoons, 1 tablespoon, 1 chopped, 1, 1 clove, 1 cup, 1/2 cup, 1/2, 1 tsp, 1/2 teaspoon, 1/2 teaspoon', 'https://www.youtube.com/watch?v=xaBo3BxKzp8'),
(53389, 'Yemeni Lahsa (Elite Shakshuka)', 'Breakfast', 'Saudi Arabian', 'Heat olive oil, sauté onion. Add tomatoes and cook. Add spices. Add eggs and mix, cover to cook. Spread liquid cheese and cover for a minute.', 'https://www.themealdb.com/images/media/meals/30s7vf1763741844.jpg', 'Egg, Onion, Tomato, Olive Oil, Allspice, Black Pepper, Liquid Cheese', '5, 1 Diced, 1 Diced, 2 tablespoons, 1/4 tsp, 1/4 tsp, 3 tablespoons', 'https://www.youtube.com/shorts/1QX-KBX6tmM'),
(53390, 'Potato Salad (Olivier Salad)', 'Vegetarian', 'Russian', 'Cube potatoes and carrots, boil in salted water with vinegar until tender. Cube sausage, pickles, and hard-boiled eggs. Mix all with peas, green onions, mayo, and dill. Refrigerate before serving.', 'https://www.themealdb.com/images/media/meals/ebvuir1699013665.jpg', 'Potatoes, Carrots, Salt, White Wine Vinegar, Eggs, Sausages, Dill, Peas, Onions, Mayonnaise', '4, 3, 1 tbs, 1/2 tbs, 4, 7 oz, 4 oz, 1 can, 4, 1 cup', 'https://www.youtube.com/watch?v=RnsWwHcpKiY'),
(53391, 'Pisto con huevos', 'Vegetarian', 'Spanish', 'Cook onions and garlic. Add peppers and cook. Mix in herbs, courgettes, and aubergine; cook for 10 mins. Add tomatoes, cook for 20 mins. Crack eggs on top, cook until set but soft. Garnish with parsley.', 'https://www.themealdb.com/images/media/meals/0nswfe1763279040.jpg', 'Olive Oil, Onion, Garlic Clove, Mixed peppers, Oregano, Thyme, Bay Leaves, Courgettes, Aubergine, Tomato, Egg, Parsley', '2 tblsp, 2, 4 Chopped, 5, 1 teaspoon, Sprigs of fresh, 4 leaves, 2 chopped, 1 chopped, 4 large, 4 large, Handful', 'https://www.youtube.com/shorts/T43aUS9bG_0'),
(53392, 'Kidney Bean Curry', 'Vegetarian', 'Indian', 'Soften onion in oil. Add garlic, ginger, and coriander stalks. Stir in spices, then tomatoes and kidney beans. Simmer for 15 mins until thick. Serve with basmati rice and fresh coriander.', 'https://www.themealdb.com/images/media/meals/sywrsu1511463066.jpg', 'Vegetable Oil, Onion, Garlic, Ginger, Coriander, Cumin, Paprika, Garam Masala, Chopped Tomatoes, Kidney Beans, Basmati Rice', '1 tbls, 1 finely chopped, 2 cloves chopped, 1 part, 1 Packet, 1 tsp, 1 tsp, 2 tsp, 400g, 400g, to serve', 'https://www.youtube.com/watch?v=Tp_PMWvIKzo'),
(53393, 'Griddled aubergines with sesame dressing', 'Vegetarian', 'Turkish', 'Griddle oiled and seasoned aubergine slices until brown and tender. For the dressing, mix yogurt, tahini, garlic, lemon juice, and herbs. Top the aubergines with the dressing and extra herbs.', 'https://www.themealdb.com/images/media/meals/yoj48r1763817100.jpg', 'Aubergine, Olive Oil, Greek Yogurt, Tahini Paste, Garlic, Lemon, Coriander, Parsley, Mint', '2 large, 2 tablespoons, 250g, 3 tablespoons, 1 clove peeled crushed, Juice of 1, Handful, Handful, Handful', 'https://www.youtube.com/watch?v=332VIeW67VM'),
(53394, 'Falafel Pita Sandwich with Tahini Sauce', 'Vegetarian', 'Syrian', 'Bake falafel at 450°F for 8-10 mins. Whisk tahini, water, lemon juice, garlic, and paprika for the sauce. Stuff pitas with falafel, lettuce, tomato, cucumber, pickle, and onion. Drizzle with sauce and harissa.', 'https://www.themealdb.com/images/media/meals/ae6clc1760524712.jpg', 'Falafel, Tahini, Water, Lemon Juice, Garlic, Paprika, Pita Bread, Lettuce, Tomato, Cucumber, Dill Pickles, Red Onions, Harissa Spice', '12, 1/4 cup, 1/4 cup, 2 tablespoons, 2 cloves, 1/4 tsp, 6, 1, 1, 1/2, 1, 1/4, 3 tsp', 'https://www.youtube.com/watch?v=wt8nApxP5fE'),
(53395, 'Kafteji', 'Vegetarian', 'Tunisian', 'Fry potato cubes until golden. Grill and skin peppers. Sauté onions with Ras el hanout. Fry pumpkin cubes until soft. Mix all vegetables in a pan, pour over whisked eggs and cook covered. Chop and mix everything together.', 'https://www.themealdb.com/images/media/meals/1bsv1q1560459826.jpg', 'Potatoes, Olive Oil, Green Pepper, Onions, Ras el hanout, Pumpkin, Eggs, Salt, Pepper', '5 Large, 2 tbs, 1, 5, 1 tbs, 500g, 24 Skinned, Pinch, Pinch', 'https://www.youtube.com/watch?v=-TFf-Zu-xQU'),
(53396, 'Sauerkraut pierogii', 'Vegetarian', 'Ukrainian', 'First, deep-fry flour-tossed shallots until crispy. For the filling, fry shallots, add sauerkraut and cabbage, and cook until soft. For the dough, mix eggs, oil, water, and flour, then knead and rest for 30 mins. Roll out dough, cut into discs, and fill with the mixture. Seal into half-moons and boil for 2 mins until they float. Serve with butter, sour cream, and crispy shallots.', 'https://www.themealdb.com/images/media/meals/gqlxgc1764368767.jpg', 'Sunflower Oil, Shallots, Sauerkraut, Hispi Cabbage, Egg, Vegetable Oil, Plain Flour, Butter, Sour Cream', '1 tablespoon, 2 chopped, 150g, 150g, 1 beaten, 1/2 tbs, 350g, 45g, 60 ml', 'https://www.youtube.com/watch?v=eVWBJt2jaPU'),
(53397, 'Stuffed Bell Peppers with Quinoa and Black Beans', 'Vegetarian', 'Mexican', 'Preheat oven to 375°F and pre-bake pepper halves for 15-20 mins. Sauté onion and garlic, then stir in cooked quinoa, black beans, corn, tomatoes, and spices. Mix in some cheese. Stuff the peppers with the mixture, top with more cheese, and bake for another 15-20 mins until tender. Garnish with cilantro.', 'https://www.themealdb.com/images/media/meals/b66myb1683207208.jpg', 'Green Pepper, Olive Oil, Onion, Garlic, Quinoa, Black Beans, Sweetcorn, Diced Tomatoes, Cumin, Chili Powder, Smoked Paprika, Salt, Pepper, Shredded Mexican Cheese, Cilantro', '4 whole, 1 tablespoon, 1 small diced, 2 cloves minced, 1 cup, 1 can, 1 cup, 1 can, 1 tsp, 1/2 tsp, 1/2 tsp, To taste, To taste, 1 1/2 cup, Chopped', '');
